func jsonValueToRawState(value JsonValue, active map[visit]bool, depth int) (any, error) {
	if err := validateJSONValueInactiveFields(value); err != nil {
		return nil, err
	}
	switch value.Kind {
	case JsonValueKindNull:
		return nil, nil
	case JsonValueKindBoolean:
		return value.Boolean, nil
	case JsonValueKindString:
		if !utf8.ValidString(value.String) {
			return nil, errors.New("JsonValue contains malformed Unicode")
		}
		return value.String, nil
	case JsonValueKindArray:
		if depth >= MaxWireJSONDepth {
			return nil, fmt.Errorf("JsonValue exceeds depth %d", MaxWireJSONDepth)
		}
		if value.Array != nil {
			key := visit{pointer: reflect.ValueOf(value.Array).Pointer(), kind: reflect.Slice}
			if active[key] {
				return nil, errors.New("JsonValue contains an array cycle")
			}
			active[key] = true
			defer delete(active, key)
		}
		items := make([]any, len(value.Array))
		for index, item := range value.Array {
			encoded, err := jsonValueToRawState(item, active, depth+1)
			if err != nil {
				return nil, err
			}
			items[index] = encoded
		}
		return items, nil
	case JsonValueKindObject:
		if depth >= MaxWireJSONDepth {
			return nil, fmt.Errorf("JsonValue exceeds depth %d", MaxWireJSONDepth)
		}
		if value.Object != nil {
			key := visit{pointer: reflect.ValueOf(value.Object).Pointer(), kind: reflect.Map}
			if active[key] {
				return nil, errors.New("JsonValue contains an object cycle")
			}
			active[key] = true
			defer delete(active, key)
		}
		items := make(map[string]any, len(value.Object))
		for key, item := range value.Object {
			if !utf8.ValidString(key) {
				return nil, errors.New("JsonValue object key contains malformed Unicode")
			}
			encoded, err := jsonValueToRawState(item, active, depth+1)
			if err != nil {
				return nil, err
			}
			items[key] = encoded
		}
		return items, nil
	default:
		return nil, fmt.Errorf("unknown JsonValue kind %q", value.Kind)
	}
}

func validateJSONValueInactiveFields(value JsonValue) error {
	invalidBoolean := value.Boolean
	invalidString := value.String != ""
	invalidArray := value.Array != nil
	invalidObject := value.Object != nil
	switch value.Kind {
	case JsonValueKindNull:
		if invalidBoolean || invalidString || invalidArray || invalidObject {
			return errors.New("JsonValue null kind has an active variant field")
		}
	case JsonValueKindBoolean:
		if invalidString || invalidArray || invalidObject {
			return errors.New("JsonValue boolean kind has an inactive variant field")
		}
	case JsonValueKindString:
		if invalidBoolean || invalidArray || invalidObject {
			return errors.New("JsonValue string kind has an inactive variant field")
		}
	case JsonValueKindArray:
		if invalidBoolean || invalidString || invalidObject {
			return errors.New("JsonValue array kind has an inactive variant field")
		}
	case JsonValueKindObject:
		if invalidBoolean || invalidString || invalidArray {
			return errors.New("JsonValue object kind has an inactive variant field")
		}
	default:
		return fmt.Errorf("unknown JsonValue kind %q", value.Kind)
	}
	return nil
}

