type visit struct {
	pointer uintptr
	kind    reflect.Kind
}

func marshalWireJSON(value any) ([]byte, error) {
	var buffer bytes.Buffer
	encoder := json.NewEncoder(&buffer)
	encoder.SetEscapeHTML(false)
	if err := encoder.Encode(value); err != nil {
		return nil, err
	}
	return bytes.TrimSuffix(buffer.Bytes(), []byte{'\n'}), nil
}

func validateGoWireValue(value reflect.Value, active map[visit]bool, depth int) error {
	if !value.IsValid() {
		return nil
	}
	if value.Kind() == reflect.Interface {
		if value.IsNil() {
			return nil
		}
		return validateGoWireValue(value.Elem(), active, depth)
	}
	if value.Kind() == reflect.Pointer && value.IsNil() {
		return nil
	}
	if value.CanInterface() {
		if marshaler, ok := value.Interface().(json.Marshaler); ok {
			encoded, err := marshaler.MarshalJSON()
			if err != nil {
				return err
			}
			raw, err := decodeWireJSON(encoded)
			if err != nil {
				return err
			}
			return validateGoWireValue(reflect.ValueOf(raw), active, depth)
		}
	}
	switch value.Kind() {
	case reflect.Pointer:
		key := visit{pointer: value.Pointer(), kind: value.Kind()}
		if active[key] {
			return errors.New("protocol value contains a cycle")
		}
		active[key] = true
		defer delete(active, key)
		return validateGoWireValue(value.Elem(), active, depth)
	case reflect.String:
		if !utf8.ValidString(value.String()) {
			return errors.New("protocol value contains malformed Unicode")
		}
	case reflect.Struct:
		if depth >= MaxWireJSONDepth {
			return fmt.Errorf("protocol value exceeds depth %d", MaxWireJSONDepth)
		}
		for index := 0; index < value.NumField(); index++ {
			if value.Type().Field(index).PkgPath != "" {
				continue
			}
			if err := validateGoWireValue(value.Field(index), active, depth+1); err != nil {
				return err
			}
		}
	case reflect.Slice:
		if value.IsNil() {
			return nil
		}
		if depth >= MaxWireJSONDepth {
			return fmt.Errorf("protocol value exceeds depth %d", MaxWireJSONDepth)
		}
		key := visit{pointer: value.Pointer(), kind: value.Kind()}
		if active[key] {
			return errors.New("protocol value contains a cycle")
		}
		active[key] = true
		defer delete(active, key)
		for index := 0; index < value.Len(); index++ {
			if err := validateGoWireValue(value.Index(index), active, depth+1); err != nil {
				return err
			}
		}
	case reflect.Array:
		if depth >= MaxWireJSONDepth {
			return fmt.Errorf("protocol value exceeds depth %d", MaxWireJSONDepth)
		}
		for index := 0; index < value.Len(); index++ {
			if err := validateGoWireValue(value.Index(index), active, depth+1); err != nil {
				return err
			}
		}
	case reflect.Map:
		if value.IsNil() {
			return nil
		}
		if depth >= MaxWireJSONDepth {
			return fmt.Errorf("protocol value exceeds depth %d", MaxWireJSONDepth)
		}
		key := visit{pointer: value.Pointer(), kind: value.Kind()}
		if active[key] {
			return errors.New("protocol value contains a cycle")
		}
		active[key] = true
		defer delete(active, key)
		iterator := value.MapRange()
		for iterator.Next() {
			if err := validateGoWireValue(iterator.Key(), active, depth+1); err != nil {
				return err
			}
			if err := validateGoWireValue(iterator.Value(), active, depth+1); err != nil {
				return err
			}
		}
	case reflect.Int, reflect.Int8, reflect.Int16, reflect.Int32, reflect.Int64:
		integer := value.Int()
		if integer < -9007199254740991 || integer > 9007199254740991 {
			return errors.New("protocol numbers must be canonical safe integers")
		}
	case reflect.Uint, reflect.Uint8, reflect.Uint16, reflect.Uint32, reflect.Uint64:
		if value.Uint() > 9007199254740991 {
			return errors.New("protocol numbers must be canonical safe integers")
		}
	case reflect.Float32, reflect.Float64:
		number := value.Float()
		if math.IsInf(number, 0) || math.IsNaN(number) || math.Trunc(number) != number || math.Signbit(number) && number == 0 || number < -9007199254740991 || number > 9007199254740991 {
			return errors.New("protocol numbers must be canonical safe integers")
		}
	}
	return nil
}

func decodeWireJSON(data []byte) (any, error) {
	if err := validateWireJSONBytes(data); err != nil {
		return nil, err
	}
	if err := rejectDuplicateJSONKeys(data); err != nil {
		return nil, err
	}
	decoder := json.NewDecoder(bytes.NewReader(data))
	decoder.UseNumber()
	var value any
	if err := decoder.Decode(&value); err != nil {
		return nil, err
	}
	var trailing any
	if err := decoder.Decode(&trailing); !errors.Is(err, io.EOF) {
		return nil, errors.New("protocol JSON must contain exactly one value")
	}
	return value, nil
}

func rejectDuplicateJSONKeys(data []byte) error {
	decoder := json.NewDecoder(bytes.NewReader(data))
	decoder.UseNumber()
	if err := scanUniqueJSONValue(decoder); err != nil {
		return err
	}
	if _, err := decoder.Token(); !errors.Is(err, io.EOF) {
		if err == nil {
			return errors.New("protocol JSON must contain exactly one value")
		}
		return err
	}
	return nil
}

func scanUniqueJSONValue(decoder *json.Decoder) error {
	token, err := decoder.Token()
	if err != nil {
		return err
	}
	delimiter, ok := token.(json.Delim)
	if !ok {
		return nil
	}
	switch delimiter {
	case '{':
		seen := map[string]bool{}
		for decoder.More() {
			rawKey, err := decoder.Token()
			if err != nil {
				return err
			}
			key, ok := rawKey.(string)
			if !ok {
				return errors.New("protocol JSON object key must be a string")
			}
			if seen[key] {
				return fmt.Errorf("protocol JSON contains duplicate object key %q", key)
			}
			seen[key] = true
			if err := scanUniqueJSONValue(decoder); err != nil {
				return err
			}
		}
		closing, err := decoder.Token()
		if err != nil {
			return err
		}
		if closing != json.Delim('}') {
			return errors.New("protocol JSON object is not closed")
		}
	case '[':
		for decoder.More() {
			if err := scanUniqueJSONValue(decoder); err != nil {
				return err
			}
		}
		closing, err := decoder.Token()
		if err != nil {
			return err
		}
		if closing != json.Delim(']') {
			return errors.New("protocol JSON array is not closed")
		}
	default:
		return errors.New("protocol JSON has an unexpected delimiter")
	}
	return nil
}

func validateWireJSONBytes(data []byte) error {
	if len(data) > MaxWireJSONBytes {
		return fmt.Errorf("protocol JSON exceeds %d UTF-8 bytes", MaxWireJSONBytes)
	}
	if !utf8.Valid(data) {
		return errors.New("protocol JSON contains malformed UTF-8")
	}
	depth := 0
	for index := 0; index < len(data); index++ {
		switch data[index] {
		case '"':
			end, err := scanJSONString(data, index)
			if err != nil {
				return err
			}
			index = end
		case '{', '[':
			depth++
			if depth > MaxWireJSONDepth {
				return fmt.Errorf("protocol JSON exceeds depth %d", MaxWireJSONDepth)
			}
		case '}', ']':
			depth--
		case '-':
			end := scanJSONToken(data, index)
			if err := validateCanonicalJSONNumber(data[index:end]); err != nil {
				return err
			}
			index = end - 1
		default:
			if data[index] >= '0' && data[index] <= '9' {
				end := scanJSONToken(data, index)
				if err := validateCanonicalJSONNumber(data[index:end]); err != nil {
					return err
				}
				index = end - 1
			}
		}
	}
	return nil
}

func scanJSONToken(data []byte, start int) int {
	index := start
	for index < len(data) && !strings.ContainsRune("{}[],: \t\r\n", rune(data[index])) {
		index++
	}
	return index
}

func validateCanonicalJSONNumber(token []byte) error {
	text := string(token)
	if !regexp.MustCompile(`^(0|-[1-9][0-9]*|[1-9][0-9]*)$`).MatchString(text) {
		return fmt.Errorf("protocol JSON number %q is not a canonical integer", text)
	}
	integer, err := strconv.ParseInt(text, 10, 64)
	if err != nil || integer < -9007199254740991 || integer > 9007199254740991 {
		return fmt.Errorf("protocol JSON number %q is outside the portable safe range", text)
	}
	return nil
}

func isCanonicalSourcePath(value string) bool {
	if value == "" || strings.HasPrefix(value, "/") || strings.ContainsAny(value, "\\\x00") {
		return false
	}
	for _, segment := range strings.Split(value, "/") {
		if segment == "" || segment == "." || segment == ".." {
			return false
		}
	}
	return true
}

func isCanonicalBinary64(text string, positive bool) bool {
	if !regexp.MustCompile(`^-?(0|[1-9][0-9]*)(\.[0-9]+)?(e[+-][1-9][0-9]*)?$`).MatchString(text) {
		return false
	}
	value, err := strconv.ParseFloat(text, 64)
	if err != nil || math.IsInf(value, 0) || math.IsNaN(value) || math.Signbit(value) && value == 0 || positive && value <= 0 {
		return false
	}
	return canonicalBinary64(value) == text
}

func canonicalBinary64(value float64) string {
	if value == 0 {
		return "0"
	}
	negative := math.Signbit(value)
	if negative {
		value = -value
	}
	scientific := strconv.FormatFloat(value, 'e', -1, 64)
	parts := strings.SplitN(scientific, "e", 2)
	digits := strings.ReplaceAll(parts[0], ".", "")
	exponent, _ := strconv.Atoi(parts[1])
	decimalPosition := exponent + 1
	var result string
	switch {
	case decimalPosition > 0 && decimalPosition <= 21:
		if decimalPosition >= len(digits) {
			result = digits + strings.Repeat("0", decimalPosition-len(digits))
		} else {
			result = digits[:decimalPosition] + "." + digits[decimalPosition:]
		}
	case decimalPosition <= 0 && decimalPosition > -6:
		result = "0." + strings.Repeat("0", -decimalPosition) + digits
	default:
		result = digits[:1]
		if len(digits) > 1 {
			result += "." + digits[1:]
		}
		if exponent >= 0 {
			result += "e+" + strconv.Itoa(exponent)
		} else {
			result += "e" + strconv.Itoa(exponent)
		}
	}
	if negative {
		return "-" + result
	}
	return result
}

type protocolVersionValue struct{ major, minor uint32 }

func parseProtocolVersion(text string) (protocolVersionValue, string, bool) {
	if !regexp.MustCompile(`^(0|[1-9][0-9]*)\.(0|[1-9][0-9]*)$`).MatchString(text) {
		return protocolVersionValue{}, "", false
	}
	parts := strings.Split(text, ".")
	major, majorErr := strconv.ParseUint(parts[0], 10, 32)
	minor, minorErr := strconv.ParseUint(parts[1], 10, 32)
	if majorErr != nil || minorErr != nil {
		return protocolVersionValue{}, "", false
	}
	return protocolVersionValue{major: uint32(major), minor: uint32(minor)}, text, true
}

func parseProtocolVersionRange(text string) (protocolVersionValue, protocolVersionValue, bool) {
	parts := strings.Split(text, "..")
	if len(parts) != 2 {
		return protocolVersionValue{}, protocolVersionValue{}, false
	}
	lower, _, lowerOK := parseProtocolVersion(parts[0])
	upper, _, upperOK := parseProtocolVersion(parts[1])
	if !lowerOK || !upperOK || lower.major != upper.major || compareProtocolVersions(lower, upper) > 0 {
		return protocolVersionValue{}, protocolVersionValue{}, false
	}
	return lower, upper, true
}

func compareProtocolVersions(left, right protocolVersionValue) int {
	if left.major < right.major || left.major == right.major && left.minor < right.minor {
		return -1
	}
	if left != right {
		return 1
	}
	return 0
}

func scanJSONString(data []byte, start int) (int, error) {
	for index := start + 1; index < len(data); index++ {
		if data[index] == '"' {
			return index, nil
		}
		if data[index] < 0x20 {
			return 0, errors.New("protocol JSON string contains an unescaped control character")
		}
		if data[index] != '\\' {
			continue
		}
		index++
		if index >= len(data) {
			return 0, errors.New("protocol JSON string has a truncated escape")
		}
		if data[index] != 'u' {
			continue
		}
		code, err := parseHexCodeUnit(data, index+1)
		if err != nil {
			return 0, err
		}
		index += 4
		if code >= 0xdc00 && code <= 0xdfff {
			return 0, errors.New("protocol JSON string has an unpaired low surrogate")
		}
		if code < 0xd800 || code > 0xdbff {
			continue
		}
		if index+6 >= len(data) || data[index+1] != '\\' || data[index+2] != 'u' {
			return 0, errors.New("protocol JSON string has an unpaired high surrogate")
		}
		low, err := parseHexCodeUnit(data, index+3)
		if err != nil || low < 0xdc00 || low > 0xdfff {
			return 0, errors.New("protocol JSON string has an invalid surrogate pair")
		}
		index += 6
	}
	return 0, errors.New("protocol JSON string is unterminated")
}

func parseHexCodeUnit(data []byte, start int) (uint16, error) {
	if start+4 > len(data) {
		return 0, errors.New("protocol JSON string has a truncated Unicode escape")
	}
	value, err := strconv.ParseUint(string(data[start:start+4]), 16, 16)
	if err != nil {
		return 0, errors.New("protocol JSON string has an invalid Unicode escape")
	}
	return uint16(value), nil
}

func validateNamed(documentID, name string, value any) error {
	document := schemaDocuments[documentID]
	definitions, ok := document["$defs"].(map[string]any)
	if !ok {
		return errors.New("generated schema has no definitions")
	}
	schema, ok := definitions[name].(map[string]any)
	if !ok {
		return fmt.Errorf("generated schema has no definition %s", name)
	}
	return validateSchema(documentID, schema, value, "$", 0)
}

func schemaEnumValues(documentID string, schema map[string]any) []any {
	for range 16 {
		if values, ok := schema["enum"].([]any); ok {
			return values
		}
		ref, ok := schema["$ref"].(string)
		if !ok {
			return nil
		}
		parts := strings.SplitN(ref, "#/$defs/", 2)
		if len(parts) != 2 {
			return nil
		}
		if parts[0] != "" {
			documentID = parts[0]
		}
		document := schemaDocuments[documentID]
		definitions, _ := document["$defs"].(map[string]any)
		schema, _ = definitions[parts[1]].(map[string]any)
		if schema == nil {
			return nil
		}
	}
	return nil
}

func validateSchema(documentID string, schema map[string]any, value any, path string, depth int) error {
	if ref, ok := schema["$ref"].(string); ok {
		parts := strings.SplitN(ref, "#/$defs/", 2)
		if len(parts) != 2 {
			return fmt.Errorf("%s has invalid generated reference", path)
		}
		if parts[0] != "" {
			documentID = parts[0]
		}
		document := schemaDocuments[documentID]
		definitions, _ := document["$defs"].(map[string]any)
		target, _ := definitions[parts[1]].(map[string]any)
		if target == nil {
			return fmt.Errorf("%s has unresolved generated reference", path)
		}
		return validateSchema(documentID, target, value, path, depth+1)
	}
	if branches, ok := schema["oneOf"].([]any); ok {
		matches := 0
		for _, rawBranch := range branches {
			branch, _ := rawBranch.(map[string]any)
			if branch != nil && validateSchema(documentID, branch, value, path, depth+1) == nil {
				matches++
			}
		}
		if matches != 1 {
			return fmt.Errorf("%s must match exactly one schema alternative", path)
		}
		return nil
	}
	typeName, _ := schema["type"].(string)
	switch typeName {
	case "null":
		if value != nil {
			return fmt.Errorf("%s must be null", path)
		}
	case "boolean":
		if _, ok := value.(bool); !ok {
			return fmt.Errorf("%s must be a boolean", path)
		}
	case "string":
		text, ok := value.(string)
		if !ok {
			return fmt.Errorf("%s must be a string", path)
		}
		if constant, ok := schema["const"].(string); ok && text != constant {
			return fmt.Errorf("%s must equal %q", path, constant)
		}
		if values, ok := schema["enum"].([]any); ok {
			matched := false
			for _, candidate := range values {
				if text == candidate {
					matched = true
					break
				}
			}
			if !matched {
				return fmt.Errorf("%s has unknown enum value %q", path, text)
			}
		}
		if pattern, ok := schema["pattern"].(string); ok && !regexp.MustCompile(strings.ReplaceAll(pattern, "(?:", "(")).MatchString(text) {
			return fmt.Errorf("%s has invalid string form", path)
		}
		if minimum, ok := schema["minLength"].(float64); ok && utf8.RuneCountInString(text) < int(minimum) {
			return fmt.Errorf("%s is too short", path)
		}
		if maximum, ok := schema["maxLength"].(float64); ok && utf8.RuneCountInString(text) > int(maximum) {
			return fmt.Errorf("%s is too long", path)
		}
		if format, _ := schema["format"].(string); format != "" {
			switch format {
			case "canonical-source-path":
				if !isCanonicalSourcePath(text) {
					return fmt.Errorf("%s is not a canonical source path", path)
				}
			case "int64-decimal":
				if !regexp.MustCompile(`^(0|-[1-9][0-9]*|[1-9][0-9]*)$`).MatchString(text) {
					return fmt.Errorf("%s is not a canonical int64", path)
				}
				if _, err := strconv.ParseInt(text, 10, 64); err != nil {
					return fmt.Errorf("%s is outside int64", path)
				}
			case "nonnegative-int64-decimal":
				if !regexp.MustCompile(`^(0|[1-9][0-9]*)$`).MatchString(text) {
					return fmt.Errorf("%s is not a canonical non-negative int64", path)
				}
				if _, err := strconv.ParseInt(text, 10, 64); err != nil {
					return fmt.Errorf("%s is outside non-negative int64", path)
				}
			case "uint64-decimal":
				if !regexp.MustCompile(`^(0|[1-9][0-9]*)$`).MatchString(text) {
					return fmt.Errorf("%s is not a canonical uint64", path)
				}
				if _, err := strconv.ParseUint(text, 10, 64); err != nil {
					return fmt.Errorf("%s is outside uint64", path)
				}
			case "positive-int64-decimal":
				integer, err := strconv.ParseInt(text, 10, 64)
				if err != nil || integer <= 0 {
					return fmt.Errorf("%s is not a positive canonical int64", path)
				}
			case "safe-integer-decimal":
				integer, err := strconv.ParseInt(text, 10, 64)
				if err != nil || integer < -9007199254740991 || integer > 9007199254740991 {
					return fmt.Errorf("%s is outside the Language 1 safe-integer range", path)
				}
			case "nonnegative-safe-integer-decimal":
				integer, err := strconv.ParseInt(text, 10, 64)
				if err != nil || integer < 0 || integer > 9007199254740991 {
					return fmt.Errorf("%s is outside the non-negative Language 1 safe-integer range", path)
				}
			case "positive-safe-integer-decimal":
				integer, err := strconv.ParseInt(text, 10, 64)
				if err != nil || integer <= 0 || integer > 9007199254740991 {
					return fmt.Errorf("%s is outside the positive Language 1 safe-integer range", path)
				}
			case "finite-binary64-decimal":
				if !isCanonicalBinary64(text, false) {
					return fmt.Errorf("%s is not a canonical finite binary64", path)
				}
			case "positive-finite-binary64-decimal":
				if !isCanonicalBinary64(text, true) {
					return fmt.Errorf("%s is not a positive canonical finite binary64", path)
				}
			case "protocol-version":
				if _, _, ok := parseProtocolVersion(text); !ok {
					return fmt.Errorf("%s is not a canonical protocol version", path)
				}
			case "protocol-version-range":
				if _, _, ok := parseProtocolVersionRange(text); !ok {
					return fmt.Errorf("%s is not a canonical ordered protocol range", path)
				}
			case "protocol-version-or-range":
				if _, _, ok := parseProtocolVersion(text); !ok {
					if _, _, rangeOK := parseProtocolVersionRange(text); !rangeOK {
						return fmt.Errorf("%s is not a canonical protocol version or range", path)
					}
				}
			case "date-time":
				if !regexp.MustCompile(`^[0-9]{4}-(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])T([01][0-9]|2[0-3]):[0-5][0-9]:[0-5][0-9](\.[0-9]{1,9})?Z$`).MatchString(text) {
					return fmt.Errorf("%s is not canonical UTC RFC 3339", path)
				}
				if _, err := time.Parse(time.RFC3339Nano, text); err != nil {
					return fmt.Errorf("%s is not a real UTC RFC 3339 calendar instant", path)
				}
			}
		}
	case "integer":
		number, ok := value.(json.Number)
		if !ok || !regexp.MustCompile(`^(0|-[1-9][0-9]*|[1-9][0-9]*)$`).MatchString(number.String()) {
			return fmt.Errorf("%s must be a canonical integer", path)
		}
		integer, err := strconv.ParseInt(number.String(), 10, 64)
		if err != nil || integer < -9007199254740991 || integer > 9007199254740991 {
			return fmt.Errorf("%s integer is outside the portable safe range", path)
		}
		if minimum, ok := schema["minimum"].(float64); ok && integer < int64(minimum) {
			return fmt.Errorf("%s is below its minimum", path)
		}
		if maximum, ok := schema["maximum"].(float64); ok && integer > int64(maximum) {
			return fmt.Errorf("%s is above its maximum", path)
		}
	case "array":
		items, ok := value.([]any)
		if !ok {
			return fmt.Errorf("%s must be an array", path)
		}
		if minimum, ok := schema["minItems"].(float64); ok && len(items) < int(minimum) {
			return fmt.Errorf("%s has too few items", path)
		}
		if maximum, ok := schema["maxItems"].(float64); ok && len(items) > int(maximum) {
			return fmt.Errorf("%s has too many items", path)
		}
		itemSchema, _ := schema["items"].(map[string]any)
		seenItems := map[string]bool{}
		for index, item := range items {
			if err := validateSchema(documentID, itemSchema, item, fmt.Sprintf("%s[%d]", path, index), depth+1); err != nil {
				return err
			}
			if unique, _ := schema["uniqueItems"].(bool); unique {
				encoded, err := json.Marshal(item)
				if err != nil {
					return fmt.Errorf("%s contains an unencodable unique item", path)
				}
				key := string(encoded)
				if seenItems[key] {
					return fmt.Errorf("%s repeats an item", path)
				}
				seenItems[key] = true
			}
		}
		if selector, _ := schema["x-layerdraw-stable-address-order"].(string); selector != "" {
			for index := 1; index < len(items); index++ {
				left, leftOK := stableAddressOrderValue(items[index-1], selector)
				right, rightOK := stableAddressOrderValue(items[index], selector)
				comparison, compared := compareStableAddresses(left, right)
				if !leftOK || !rightOK || !compared || comparison >= 0 {
					return fmt.Errorf("%s is not in strict StableSymbol order", path)
				}
			}
		}
		if ordered, _ := schema["x-layerdraw-canonical-identifier-order"].(bool); ordered {
			for index := 1; index < len(items); index++ {
				left, leftOK := items[index-1].(string)
				right, rightOK := items[index].(string)
				if !leftOK || !rightOK || !isCanonicalLocalIdentifier(left) || !isCanonicalLocalIdentifier(right) || left >= right {
					return fmt.Errorf("%s is not in strict canonical identifier order", path)
				}
			}
			if len(items) == 1 {
				if text, ok := items[0].(string); !ok || !isCanonicalLocalIdentifier(text) {
					return fmt.Errorf("%s contains a noncanonical identifier", path)
				}
			}
		}
		if ordered, _ := schema["x-layerdraw-canonical-enum-order"].(bool); ordered {
			values := schemaEnumValues(documentID, itemSchema)
			ranks := map[string]int{}
			for index, raw := range values {
				if text, ok := raw.(string); ok {
					ranks[text] = index
				}
			}
			for index := 1; index < len(items); index++ {
				left, leftOK := items[index-1].(string)
				right, rightOK := items[index].(string)
				leftRank, leftRankOK := ranks[left]
				rightRank, rightRankOK := ranks[right]
				if !leftOK || !rightOK || !leftRankOK || !rightRankOK || leftRank >= rightRank {
					return fmt.Errorf("%s is not in strict schema-enum order", path)
				}
			}
		}
		if ordered, _ := schema["x-layerdraw-unicode-scalar-order"].(bool); ordered {
			for index := 1; index < len(items); index++ {
				left, leftOK := items[index-1].(string)
				right, rightOK := items[index].(string)
				if !leftOK || !rightOK || compareUnicodeScalars(left, right) >= 0 {
					return fmt.Errorf("%s is not in strict Unicode scalar order", path)
				}
			}
		}
		if ordered, _ := schema["x-layerdraw-state-read-order"].(bool); ordered {
			if err := validateStateReadOrder(path, items); err != nil {
				return err
			}
		}
		if profile, _ := schema["x-layerdraw-canonical-collection-order"].(string); profile != "" {
			if err := validateCanonicalCollectionOrder(path, items, profile); err != nil {
				return err
			}
		}
	case "object":
		object, ok := value.(map[string]any)
		if !ok {
			return fmt.Errorf("%s must be an object", path)
		}
		properties, _ := schema["properties"].(map[string]any)
		required, _ := schema["required"].([]any)
		for _, rawName := range required {
			name, _ := rawName.(string)
			if _, exists := object[name]; !exists {
				return fmt.Errorf("%s.%s is required", path, name)
			}
		}
		for name, item := range object {
			if propertyNames, ok := schema["propertyNames"].(map[string]any); ok {
				if err := validateSchema(documentID, propertyNames, name, path+" property name", depth+1); err != nil {
					return err
				}
			}
			if rawProperty, exists := properties[name]; exists {
				property, _ := rawProperty.(map[string]any)
				if err := validateSchema(documentID, property, item, path+"."+name, depth+1); err != nil {
					return err
				}
				continue
			}
			switch additional := schema["additionalProperties"].(type) {
			case bool:
				if !additional {
					return fmt.Errorf("%s contains unknown property %q", path, name)
				}
			case map[string]any:
				if err := validateSchema(documentID, additional, item, path+"."+name, depth+1); err != nil {
					return err
				}
			default:
				return fmt.Errorf("%s contains property not covered by generated schema", path)
			}
		}
		if rawUnion, ok := schema["x-layerdraw-tagged-union"].(map[string]any); ok {
			property, _ := rawUnion["property"].(string)
			tag := fmt.Sprint(object[property])
			variants, _ := rawUnion["variants"].(map[string]any)
			rawVariant, exists := variants[tag]
			if !exists {
				return fmt.Errorf("%s has unknown tagged union value %q", path, tag)
			}
			variant, _ := rawVariant.(map[string]any)
			if err := validatePresenceRule(path, object, variant); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-diff-source"].(bool); enabled {
			if err := validateDiffSource(path, object); err != nil {
				return err
			}
		}
		if rawRule, ok := schema["x-layerdraw-operator-value"].(map[string]any); ok {
			operatorProperty, _ := rawRule["operator"].(string)
			valueProperty, _ := rawRule["value"].(string)
			operator, operatorPresent := object[operatorProperty].(string)
			if operatorPresent {
				valueless := false
				if values, ok := rawRule["valueless"].([]any); ok {
					for _, candidate := range values {
						if operator == candidate {
							valueless = true
						}
					}
				}
				_, valuePresent := object[valueProperty]
				if valueless && valuePresent {
					return fmt.Errorf("%s operator %s forbids %s", path, operator, valueProperty)
				}
				if !valueless && !valuePresent {
					return fmt.Errorf("%s operator %s requires %s", path, operator, valueProperty)
				}
			}
		}
		if enabled, _ := schema["x-layerdraw-protocol-offer"].(bool); enabled {
			if err := validateProtocolOffer(path, object); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-limit-capability"].(bool); enabled {
			if err := validateLimitCapability(path, object); err != nil {
				return err
			}
		}
		if rules, ok := schema["x-layerdraw-unique-array-keys"].([]any); ok {
			for _, rawRule := range rules {
				rule, _ := rawRule.(map[string]any)
				arrayName, _ := rule["array"].(string)
				propertyName, _ := rule["property"].(string)
				items, _ := object[arrayName].([]any)
				seen := map[string]bool{}
				for _, rawItem := range items {
					item, _ := rawItem.(map[string]any)
					key, _ := item[propertyName].(string)
					if seen[key] {
						return fmt.Errorf("%s.%s repeats %s %q", path, arrayName, propertyName, key)
					}
					seen[key] = true
				}
			}
		}
		if rules, ok := schema["x-layerdraw-disjoint-arrays"].([]any); ok {
			for _, rawRule := range rules {
				rule, _ := rawRule.(map[string]any)
				leftName, _ := rule["left"].(string)
				rightName, _ := rule["right"].(string)
				left, _ := object[leftName].([]any)
				right, _ := object[rightName].([]any)
				seen := map[string]bool{}
				for _, rawItem := range left {
					item, _ := rawItem.(string)
					seen[item] = true
				}
				for _, rawItem := range right {
					item, _ := rawItem.(string)
					if seen[item] {
						return fmt.Errorf("%s.%s and %s.%s overlap at %q", path, leftName, path, rightName, item)
					}
				}
			}
		}
		if rules, ok := schema["x-layerdraw-disjoint-array-keys"].([]any); ok {
			if err := validateDisjointArrayKeys(path, object, rules); err != nil {
				return err
			}
		}
		if rules, ok := schema["x-layerdraw-ordered-pairs"].([]any); ok {
			if err := validateOrderedPairs(path, object, rules); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-outcome-envelope"].(bool); enabled {
			outcome, _ := object["outcome"].(string)
			switch outcome {
			case "success":
				if _, ok := object["payload"]; !ok {
					return fmt.Errorf("%s success requires payload", path)
				}
				if _, ok := object["failure"]; ok {
					return fmt.Errorf("%s success forbids failure", path)
				}
			case "rejected":
				if _, ok := object["payload"]; ok {
					return fmt.Errorf("%s rejected outcome forbids payload", path)
				}
				if _, ok := object["failure"]; ok {
					return fmt.Errorf("%s rejected outcome forbids failure", path)
				}
				diagnostics, _ := object["diagnostics"].([]any)
				if len(diagnostics) == 0 {
					return fmt.Errorf("%s rejected outcome requires diagnostics", path)
				}
			case "failed", "cancelled":
				if _, ok := object["payload"]; ok {
					return fmt.Errorf("%s %s outcome forbids payload", path, outcome)
				}
				failure, ok := object["failure"].(map[string]any)
				if !ok {
					return fmt.Errorf("%s %s outcome requires failure", path, outcome)
				}
				if category, present := failure["workbench_category"].(string); present {
					if outcome == "cancelled" && category != "cancelled" || outcome == "failed" && category == "cancelled" {
						return fmt.Errorf("%s outcome contradicts Workbench failure category", path)
					}
				}
			}
		}
		if enabled, _ := schema["x-layerdraw-ordered-range"].(bool); enabled {
			start, startOK := object["start_byte"].(string)
			end, endOK := object["end_byte"].(string)
			startValue, startErr := strconv.ParseUint(start, 10, 64)
			endValue, endErr := strconv.ParseUint(end, 10, 64)
			if !startOK || !endOK || startErr != nil || endErr != nil || startValue > endValue {
				return fmt.Errorf("%s range start_byte must not exceed end_byte", path)
			}
		}
		if rules, ok := schema["x-layerdraw-address-owners"].([]any); ok {
			if err := validateAddressOwners(path, object, rules); err != nil {
				return err
			}
		}
		if rule, ok := schema["x-layerdraw-address-terminal-id"].(map[string]any); ok {
			addressProperty, _ := rule["address"].(string)
			idProperty, _ := rule["id"].(string)
			address, addressOK := object[addressProperty].(string)
			id, idOK := object[idProperty].(string)
			parts := strings.Split(address, ":")
			if !addressOK || !idOK || len(parts) == 0 || parts[len(parts)-1] != id {
				return fmt.Errorf("%s.%s must equal the terminal ID of %s.%s", path, idProperty, path, addressProperty)
			}
		}
		if rawRules, ok := schema["x-layerdraw-stable-address-roles"].([]any); ok {
			if err := validateStableAddressRoles(path, object, rawRules); err != nil {
				return err
			}
		}
		if predicateKind, _ := schema["x-layerdraw-recipe-predicate"].(string); predicateKind != "" {
			if err := validateRecipePredicateConsistency(path, object, predicateKind); err != nil {
				return err
			}
		}
		if projectionKind, _ := schema["x-layerdraw-view-projection"].(string); projectionKind != "" {
			if err := validateViewProjectionConsistency(path, object, projectionKind); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-export-recipe"].(bool); enabled {
			if err := validateExportRecipeConsistency(path, object); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-query-parameter"].(bool); enabled {
			if err := validateQueryParameterConsistency(path, object); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-query-recipe"].(bool); enabled {
			if err := validateQueryRecipeConsistency(path, object); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-recipe-scalar"].(bool); enabled {
			if err := validateRecipeScalarConsistency(path, object); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-state-read"].(bool); enabled {
			if err := validateStateReadConsistency(path, object); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-view-recipe"].(bool); enabled {
			if err := validateViewRecipeConsistency(path, object); err != nil {
				return err
			}
		}
		if enabled, _ := schema["x-layerdraw-child-set"].(bool); enabled {
			if err := validateChildSetConsistency(path, object); err != nil {
				return err
			}
		}
		if profile, _ := schema["x-layerdraw-protocol-invariant"].(string); profile != "" {
			if err := validateProtocolInvariant(path, object, profile); err != nil {
				return err
			}
		}
	default:
		return fmt.Errorf("%s uses unsupported generated schema type %q", path, typeName)
	}
	return nil
}

func stableAddressOrderValue(value any, selector string) (string, bool) {
	if selector == "$item" {
		text, ok := value.(string)
		return text, ok
	}
	object, ok := value.(map[string]any)
	if !ok {
		return "", false
	}
	text, ok := object[selector].(string)
	return text, ok
}

func isCanonicalLocalIdentifier(value string) bool {
	return regexp.MustCompile(`^[a-z][a-z0-9_]*$`).MatchString(value)
}

func compareUnicodeScalars(left, right string) int {
	leftRunes, rightRunes := []rune(left), []rune(right)
	for index := 0; index < len(leftRunes) && index < len(rightRunes); index++ {
		if leftRunes[index] < rightRunes[index] {
			return -1
		}
		if leftRunes[index] > rightRunes[index] {
			return 1
		}
	}
	if len(leftRunes) < len(rightRunes) {
		return -1
	}
	if len(leftRunes) > len(rightRunes) {
		return 1
	}
	return 0
}

func compareCanonicalUnsignedDecimals(left, right string) (int, bool) {
	canonical := regexp.MustCompile(`^(0|[1-9][0-9]*)$`)
	if !canonical.MatchString(left) || !canonical.MatchString(right) {
		return 0, false
	}
	if len(left) < len(right) {
		return -1, true
	}
	if len(left) > len(right) {
		return 1, true
	}
	if left < right {
		return -1, true
	}
	if left > right {
		return 1, true
	}
	return 0, true
}

func semanticSubjectKindRank(kind string) (int, bool) {
	kinds := []string{"project", "pack", "entity_type", "relation_type", "layer", "entity", "relation", "query", "view", "reference", "entity_type_column", "entity_type_constraint", "relation_type_column", "relation_type_constraint", "entity_row", "relation_row", "query_parameter", "view_table_column", "view_export"}
	for index, candidate := range kinds {
		if kind == candidate {
			return index, true
		}
	}
	return 0, false
}

func compareText(left, right string) int {
	return compareUnicodeScalars(left, right)
}

func compareStableAddressValues(left, right string) (int, bool) {
	return compareStableAddresses(left, right)
}

func sourceOriginOrder(raw any) (int, string, bool) {
	object, ok := raw.(map[string]any)
	if !ok {
		return 0, "", false
	}
	kind, ok := object["kind"].(string)
	if !ok {
		return 0, "", false
	}
	switch kind {
	case "project":
		return 0, "", true
	case "pack":
		address, ok := object["pack_address"].(string)
		return 1, address, ok
	default:
		return 0, "", false
	}
}

func compareModuleOrder(left, right map[string]any) (int, bool) {
	leftRank, leftPack, leftOK := sourceOriginOrder(left["origin"])
	rightRank, rightPack, rightOK := sourceOriginOrder(right["origin"])
	leftPath, leftPathOK := left["module_path"].(string)
	rightPath, rightPathOK := right["module_path"].(string)
	if !leftOK || !rightOK || !leftPathOK || !rightPathOK {
		return 0, false
	}
	if leftRank != rightRank {
		if leftRank < rightRank {
			return -1, true
		}
		return 1, true
	}
	if compared := compareText(leftPack, rightPack); compared != 0 {
		return compared, true
	}
	return compareText(leftPath, rightPath), true
}

func compareRangePosition(left, right map[string]any) (int, bool) {
	leftStart, leftStartOK := left["start_byte"].(string)
	rightStart, rightStartOK := right["start_byte"].(string)
	leftEnd, leftEndOK := left["end_byte"].(string)
	rightEnd, rightEndOK := right["end_byte"].(string)
	if !leftStartOK || !rightStartOK || !leftEndOK || !rightEndOK {
		return 0, false
	}
	if compared, ok := compareCanonicalUnsignedDecimals(leftStart, rightStart); !ok {
		return 0, false
	} else if compared != 0 {
		return compared, true
	}
	return compareCanonicalUnsignedDecimals(leftEnd, rightEnd)
}

func compareCanonicalCollection(profile string, left, right any) (int, bool) {
	a, aOK := left.(map[string]any)
	b, bOK := right.(map[string]any)
	if !aOK || !bOK {
		return 0, false
	}
	stable := func(property string) (int, bool) {
		l, lOK := a[property].(string)
		r, rOK := b[property].(string)
		if !lOK || !rOK {
			return 0, false
		}
		return compareStableAddressValues(l, r)
	}
	text := func(property string) (int, bool) {
		l, lOK := a[property].(string)
		r, rOK := b[property].(string)
		if !lOK || !rOK {
			return 0, false
		}
		return compareText(l, r), true
	}
	kind := func(property string) (int, bool) {
		l, lOK := a[property].(string)
		r, rOK := b[property].(string)
		if !lOK || !rOK {
			return 0, false
		}
		lr, lok := semanticSubjectKindRank(l)
		rr, rok := semanticSubjectKindRank(r)
		if !lok || !rok {
			return 0, false
		}
		if lr < rr {
			return -1, true
		}
		if lr > rr {
			return 1, true
		}
		return 0, true
	}
	rangeValue := func() (int, bool) {
		l, lOK := a["range"].(map[string]any)
		r, rOK := b["range"].(map[string]any)
		if !lOK || !rOK {
			return 0, false
		}
		return compareRangePosition(l, r)
	}
	identity := func() (int, bool) {
		l, _ := a["before_address"].(string)
		if l == "" {
			l, _ = a["after_address"].(string)
		}
		r, _ := b["before_address"].(string)
		if r == "" {
			r, _ = b["after_address"].(string)
		}
		if l == "" || r == "" {
			return 0, false
		}
		return compareStableAddressValues(l, r)
	}
	conflictAddress := func(property string) func() (int, bool) {
		return func() (int, bool) {
			l, _ := a[property].(string)
			r, _ := b[property].(string)
			if l == "" || r == "" {
				return compareText(l, r), true
			}
			return compareStableAddressValues(l, r)
		}
	}
	conflictKind := func() (int, bool) {
		rank := func(value string) int {
			switch value {
			case "stale_revision":
				return 0
			case "subject_changed":
				return 1
			case "subtree_changed":
				return 2
			case "child_set_changed":
				return 3
			case "same_field_changed":
				return 4
			case "delete_vs_update":
				return 5
			case "duplicate_identity":
				return 6
			case "reference_broken":
				return 7
			case "schema_row_incompatible":
				return 8
			case "placement_changed":
				return 9
			case "project_identity_changed":
				return 10
			default:
				return -1
			}
		}
		l, lOK := a["kind"].(string)
		r, rOK := b["kind"].(string)
		if !lOK || !rOK {
			return 0, false
		}
		lr, rr := rank(l), rank(r)
		if lr < 0 || rr < 0 {
			return 0, false
		}
		if lr < rr {
			return -1, true
		}
		if lr > rr {
			return 1, true
		}
		return 0, true
	}
	conflictChildKind := func() (int, bool) {
		l, _ := a["child_kind"].(string)
		r, _ := b["child_kind"].(string)
		if l == "" || r == "" {
			return compareText(l, r), true
		}
		lr, lok := semanticSubjectKindRank(l)
		rr, rok := semanticSubjectKindRank(r)
		if !lok || !rok {
			return 0, false
		}
		if lr < rr {
			return -1, true
		}
		if lr > rr {
			return 1, true
		}
		return 0, true
	}
	pathProperty := func(property string) func() (int, bool) {
		return func() (int, bool) {
			l, lOK := a[property].([]any)
			r, rOK := b[property].([]any)
			if !lOK {
				l = []any{}
			}
			if !rOK {
				r = []any{}
			}
			for index := 0; index < len(l) && index < len(r); index++ {
				ls, lok := l[index].(string)
				rs, rok := r[index].(string)
				if !lok || !rok {
					return 0, false
				}
				if compared := compareText(ls, rs); compared != 0 {
					return compared, true
				}
			}
			if len(l) < len(r) {
				return -1, true
			}
			if len(l) > len(r) {
				return 1, true
			}
			return 0, true
		}
	}
	path := pathProperty("path")
	optionalSourceRange := func() (int, bool) {
		l, lOK := a["source_range"].(map[string]any)
		r, rOK := b["source_range"].(map[string]any)
		if !lOK || !rOK {
			if lOK {
				return 1, true
			}
			if rOK {
				return -1, true
			}
			return 0, true
		}
		return compareRangePosition(l, r)
	}
	chain := func(comparisons ...func() (int, bool)) (int, bool) {
		for _, comparison := range comparisons {
			value, ok := comparison()
			if !ok || value != 0 {
				return value, ok
			}
		}
		return 0, true
	}
	switch profile {
	case "authored_field_path":
		return pathProperty("tokens")()
	case "authoring_impact":
		address := func() (int, bool) {
			l, _ := a["subject_address"].(string)
			if l == "" {
				l, _ = a["owner_address"].(string)
			}
			r, _ := b["subject_address"].(string)
			if r == "" {
				r, _ = b["owner_address"].(string)
			}
			if l == "" || r == "" {
				return compareText(l, r), true
			}
			return compareStableAddressValues(l, r)
		}
		return chain(address, func() (int, bool) { return text("capability") }, func() (int, bool) { return text("action") })
	case "bounded_text_chunk":
		address := func() (int, bool) {
			l, _ := a["address"].(string)
			if l == "" {
				l, _ = a["owner_address"].(string)
			}
			r, _ := b["address"].(string)
			if r == "" {
				r, _ = b["owner_address"].(string)
			}
			if l == "" || r == "" {
				return 0, false
			}
			return compareStableAddressValues(l, r)
		}
		offset := func() (int, bool) {
			lc, _ := a["source_chunk"].(map[string]any)
			if lc == nil {
				lc, _ = a["text_chunk"].(map[string]any)
			}
			rc, _ := b["source_chunk"].(map[string]any)
			if rc == nil {
				rc, _ = b["text_chunk"].(map[string]any)
			}
			l, lOK := lc["offset"].(string)
			r, rOK := rc["offset"].(string)
			if !lOK || !rOK {
				return 0, false
			}
			return compareCanonicalUnsignedDecimals(l, r)
		}
		return chain(address, offset)
	case "child_set":
		return chain(func() (int, bool) { return stable("owner_address") }, func() (int, bool) { return kind("child_kind") })
	case "conflict":
		return chain(conflictKind, conflictAddress("target_address"), conflictAddress("owner_address"), conflictChildKind, path)
	case "reference_id":
		return text("id")
	case "subject_kind":
		return kind("kind")
	case "module_scope":
		leftModule, leftOK := a["module"].(map[string]any)
		rightModule, rightOK := b["module"].(map[string]any)
		if !leftOK || !rightOK {
			return 0, false
		}
		return compareModuleOrder(leftModule, rightModule)
	case "neighbor":
		l, lOK := a["traversal_index"].(string)
		r, rOK := b["traversal_index"].(string)
		if !lOK || !rOK {
			return 0, false
		}
		return compareCanonicalUnsignedDecimals(l, r)
	case "source_file":
		return compareModuleOrder(a, b)
	case "source_patch":
		leftRange, leftOK := a["source_range"].(map[string]any)
		rightRange, rightOK := b["source_range"].(map[string]any)
		if !leftOK || !rightOK {
			return 0, false
		}
		if compared, ok := compareModuleOrder(leftRange, rightRange); !ok || compared != 0 {
			return compared, ok
		}
		return compareRangePosition(leftRange, rightRange)
	case "semantic_diff":
		return chain(identity, func() (int, bool) { return text("kind") })
	case "semantic_map_entry":
		return text("key")
	case "source_diff":
		module := func(value map[string]any) map[string]any {
			if sourceRange, ok := value["source_range"].(map[string]any); ok {
				return sourceRange
			}
			if before, ok := value["before_module"].(map[string]any); ok {
				return before
			}
			after, _ := value["after_module"].(map[string]any)
			return after
		}
		primary := func() (int, bool) {
			l, r := module(a), module(b)
			if l == nil || r == nil {
				return 0, false
			}
			return compareModuleOrder(l, r)
		}
		after := func() (int, bool) {
			l, lOK := a["after_module"].(map[string]any)
			r, rOK := b["after_module"].(map[string]any)
			if !lOK || !rOK {
				if lOK {
					return 1, true
				}
				if rOK {
					return -1, true
				}
				return 0, true
			}
			return compareModuleOrder(l, r)
		}
		return chain(primary, func() (int, bool) { return text("kind") }, optionalSourceRange, after)
	case "source_range":
		if compared, ok := compareModuleOrder(a, b); !ok || compared != 0 {
			return compared, ok
		}
		return compareRangePosition(a, b)
	case "subgraph":
		l, lOK := a["traversal_index"].(string)
		r, rOK := b["traversal_index"].(string)
		if !lOK || !rOK {
			return 0, false
		}
		return compareCanonicalUnsignedDecimals(l, r)
	case "source_asset":
		return chain(func() (int, bool) { return stable("subject_address") }, func() (int, bool) { return text("locator") })
	case "semantic_reference":
		return chain(func() (int, bool) { return stable("source_address") }, rangeValue, func() (int, bool) { return stable("target_address") }, func() (int, bool) { return kind("target_kind") }, func() (int, bool) { return text("via") })
	case "source_binding":
		owner := func() (int, bool) {
			l, _ := a["target_owner_address"].(string)
			r, _ := b["target_owner_address"].(string)
			if l == "" || r == "" {
				return compareText(l, r), true
			}
			return compareStableAddressValues(l, r)
		}
		return chain(func() (int, bool) { return stable("source_address") }, rangeValue, func() (int, bool) { return stable("target_address") }, func() (int, bool) { return kind("target_kind") }, owner, func() (int, bool) { return text("via") })
	case "export_binding":
		module := func() (int, bool) {
			l, lOK := a["module"].(map[string]any)
			r, rOK := b["module"].(map[string]any)
			if !lOK || !rOK {
				return 0, false
			}
			return compareModuleOrder(l, r)
		}
		boolean := func() (int, bool) {
			l, lOK := a["re_export"].(bool)
			r, rOK := b["re_export"].(bool)
			if !lOK || !rOK {
				return 0, false
			}
			if l == r {
				return 0, true
			}
			if !l {
				return -1, true
			}
			return 1, true
		}
		return chain(module, rangeValue, func() (int, bool) { return text("public_name") }, func() (int, bool) { return stable("target_address") }, boolean)
	default:
		return 0, false
	}
}

func validateCanonicalCollectionOrder(path string, items []any, profile string) error {
	for index := 1; index < len(items); index++ {
		comparison, ok := compareCanonicalCollection(profile, items[index-1], items[index])
		if !ok || comparison >= 0 {
			return fmt.Errorf("%s is not in strict %s order", path, profile)
		}
		if profile == "source_patch" {
			left, leftOK := items[index-1].(map[string]any)
			right, rightOK := items[index].(map[string]any)
			leftRange, leftRangeOK := left["source_range"].(map[string]any)
			rightRange, rightRangeOK := right["source_range"].(map[string]any)
			if !leftOK || !rightOK || !leftRangeOK || !rightRangeOK {
				return fmt.Errorf("%s contains an invalid source patch", path)
			}
			if moduleComparison, moduleOK := compareModuleOrder(leftRange, rightRange); moduleOK && moduleComparison == 0 {
				leftEnd, leftEndOK := leftRange["end_byte"].(string)
				rightStart, rightStartOK := rightRange["start_byte"].(string)
				overlap, decimalsOK := compareCanonicalUnsignedDecimals(leftEnd, rightStart)
				if !leftEndOK || !rightStartOK || !decimalsOK || overlap > 0 {
					return fmt.Errorf("%s contains overlapping source patches", path)
				}
			}
		}
	}
	return nil
}

func validateChildSetConsistency(path string, object map[string]any) error {
	owner, ownerOK := object["owner_address"].(string)
	childKind, childOK := object["child_kind"].(string)
	ownerKind, _, valid := stableAddressSubject(owner)
	if !ownerOK || !childOK || !valid {
		return fmt.Errorf("%s has invalid ChildSet authority", path)
	}
	allowed := map[string]map[string]bool{
		"project":       {"entity_type": true, "relation_type": true, "layer": true, "entity": true, "relation": true, "query": true, "view": true, "reference": true},
		"pack":          {"entity_type": true, "relation_type": true, "query": true, "view": true, "reference": true},
		"entity_type":   {"entity_type_column": true, "entity_type_constraint": true},
		"relation_type": {"relation_type_column": true, "relation_type_constraint": true},
		"entity":        {"entity_row": true}, "relation": {"relation_row": true}, "query": {"query_parameter": true}, "view": {"view_table_column": true, "view_export": true},
	}
	if !allowed[ownerKind][childKind] {
		return fmt.Errorf("%s has an impossible owner/child kind pair", path)
	}
	return nil
}

func validateOrderedPairs(path string, object map[string]any, rules []any) error {
	for _, rawRule := range rules {
		rule, _ := rawRule.(map[string]any)
		lowerProperty, _ := rule["lower"].(string)
		upperProperty, _ := rule["upper"].(string)
		comparison, _ := rule["comparison"].(string)
		rawLower, lowerPresent := object[lowerProperty]
		rawUpper, upperPresent := object[upperProperty]
		if !lowerPresent || !upperPresent {
			continue
		}
		lower, lowerOK := rawLower.(string)
		upper, upperOK := rawUpper.(string)
		if !lowerOK || !upperOK {
			return fmt.Errorf("%s ordered pair requires string values", path)
		}
		switch comparison {
		case "unsigned_decimal":
			ordered, ok := compareCanonicalUnsignedDecimals(lower, upper)
			if !ok || ordered > 0 {
				return fmt.Errorf("%s.%s must not exceed %s.%s", path, lowerProperty, path, upperProperty)
			}
		case "finite_binary64":
			lowerValue, lowerErr := strconv.ParseFloat(lower, 64)
			upperValue, upperErr := strconv.ParseFloat(upper, 64)
			if lowerErr != nil || upperErr != nil || math.IsNaN(lowerValue) || math.IsNaN(upperValue) || math.IsInf(lowerValue, 0) || math.IsInf(upperValue, 0) || lowerValue > upperValue {
				return fmt.Errorf("%s.%s must not exceed %s.%s", path, lowerProperty, path, upperProperty)
			}
		default:
			return fmt.Errorf("%s has unsupported ordered-pair comparison", path)
		}
	}
	return nil
}

func validateDisjointArrayKeys(path string, object map[string]any, rules []any) error {
	for _, rawRule := range rules {
		rule, _ := rawRule.(map[string]any)
		arrayProperty, _ := rule["array"].(string)
		keyProperty, _ := rule["property"].(string)
		stringsProperty, _ := rule["strings"].(string)
		items, itemsOK := object[arrayProperty].([]any)
		if _, exists := object[arrayProperty]; !exists {
			items, itemsOK = []any{}, true
		}
		stringsArray, stringsOK := object[stringsProperty].([]any)
		if _, exists := object[stringsProperty]; !exists {
			stringsArray, stringsOK = []any{}, true
		}
		if !itemsOK || !stringsOK {
			return fmt.Errorf("%s disjoint array-key assertion requires arrays", path)
		}
		reserved := map[string]bool{}
		for _, raw := range stringsArray {
			text, ok := raw.(string)
			if !ok {
				return fmt.Errorf("%s.%s contains a non-string", path, stringsProperty)
			}
			reserved[text] = true
		}
		for _, raw := range items {
			item, ok := raw.(map[string]any)
			if !ok {
				return fmt.Errorf("%s.%s contains a non-object", path, arrayProperty)
			}
			key, ok := item[keyProperty].(string)
			if !ok {
				return fmt.Errorf("%s.%s item has no string %s", path, arrayProperty, keyProperty)
			}
			if reserved[key] {
				return fmt.Errorf("%s.%s %s %q overlaps %s", path, arrayProperty, keyProperty, key, stringsProperty)
			}
		}
	}
	return nil
}

func validateRecipeScalarConsistency(path string, object map[string]any) error {
	kind, _ := object["kind"].(string)
	text, _ := object["string_value"].(string)
	switch kind {
	case "date":
		if !regexp.MustCompile(`^[0-9]{4}-[0-9]{2}-[0-9]{2}$`).MatchString(text) || strings.HasPrefix(text, "0000-") {
			return fmt.Errorf("%s contains an invalid date", path)
		}
		if _, err := time.Parse("2006-01-02", text); err != nil {
			return fmt.Errorf("%s contains an invalid date", path)
		}
	case "datetime":
		if strings.HasPrefix(text, "0000-") || !regexp.MustCompile(`^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}(?:\.[0-9]{1,3})?Z$`).MatchString(text) {
			return fmt.Errorf("%s contains an invalid datetime", path)
		}
		parsed, err := time.Parse(time.RFC3339Nano, text)
		if err != nil || parsed.UTC().Format(time.RFC3339Nano) != text {
			return fmt.Errorf("%s contains a non-canonical datetime", path)
		}
	case "enum":
		if text == "" {
			return fmt.Errorf("%s contains an empty enum value", path)
		}
	}
	return nil
}

func validCanonicalHostname(value string) bool {
	if value == "" || len(value) > 253 || value != strings.ToLower(value) || strings.HasSuffix(value, ".") {
		return false
	}
	for _, label := range strings.Split(value, ".") {
		if len(label) == 0 || len(label) > 63 || label[0] == '-' || label[len(label)-1] == '-' || !regexp.MustCompile(`^[a-z0-9-]+$`).MatchString(label) {
			return false
		}
	}
	return true
}

func canonicalURIAlpha(ch byte) bool { return ch >= 'A' && ch <= 'Z' || ch >= 'a' && ch <= 'z' }
func canonicalURIDigit(ch byte) bool { return ch >= '0' && ch <= '9' }
func canonicalURIHex(ch byte) bool {
	return canonicalURIDigit(ch) || ch >= 'A' && ch <= 'F' || ch >= 'a' && ch <= 'f'
}
func canonicalURIUnreserved(ch byte) bool {
	return canonicalURIAlpha(ch) || canonicalURIDigit(ch) || strings.ContainsRune("-._~", rune(ch))
}
func canonicalURICharacter(ch byte) bool {
	return canonicalURIUnreserved(ch) || strings.ContainsRune(":/?#[]@!$&'()*+,;=%", rune(ch))
}
func canonicalURIScheme(value string) bool {
	if value == "" || !canonicalURIAlpha(value[0]) {
		return false
	}
	for index := 1; index < len(value); index++ {
		if !canonicalURIAlpha(value[index]) && !canonicalURIDigit(value[index]) && !strings.ContainsRune("+.-", rune(value[index])) {
			return false
		}
	}
	return true
}
func canonicalURIAllDigits(value string) bool {
	for index := range len(value) {
		if !canonicalURIDigit(value[index]) {
			return false
		}
	}
	return true
}
func canonicalURIComponent(value string, allowEmpty bool, extra string) bool {
	if value == "" {
		return allowEmpty
	}
	for index := 0; index < len(value); index++ {
		if value[index] == '%' {
			if index+2 >= len(value) || !canonicalURIHex(value[index+1]) || !canonicalURIHex(value[index+2]) {
				return false
			}
			index += 2
			continue
		}
		if !canonicalURIUnreserved(value[index]) && !strings.ContainsRune("!$&'()*+,;="+extra, rune(value[index])) {
			return false
		}
	}
	return true
}
func canonicalIPLiteral(value string) bool {
	if address, err := netip.ParseAddr(value); err == nil {
		return address.Is6() && address.Zone() == ""
	}
	if len(value) < 4 || value[0] != 'v' && value[0] != 'V' {
		return false
	}
	dot := strings.IndexByte(value, '.')
	if dot < 2 {
		return false
	}
	for index := 1; index < dot; index++ {
		if !canonicalURIHex(value[index]) {
			return false
		}
	}
	return value[dot+1:] != "" && canonicalURIComponent(value[dot+1:], false, ":")
}
func canonicalURIAuthority(value string) bool {
	if strings.Count(value, "@") > 1 {
		return false
	}
	hostPort := value
	if userInfo, rest, ok := strings.Cut(value, "@"); ok {
		if !canonicalURIComponent(userInfo, true, ":") {
			return false
		}
		hostPort = rest
	}
	if strings.HasPrefix(hostPort, "[") {
		close := strings.IndexByte(hostPort, ']')
		if close <= 1 {
			return false
		}
		literal, rest := hostPort[1:close], hostPort[close+1:]
		return canonicalIPLiteral(literal) && (rest == "" || strings.HasPrefix(rest, ":") && canonicalURIAllDigits(rest[1:]))
	}
	if strings.ContainsAny(hostPort, "[]") {
		return false
	}
	host := hostPort
	if colon := strings.LastIndexByte(hostPort, ':'); colon >= 0 {
		host = hostPort[:colon]
		if strings.Contains(host, ":") || !canonicalURIAllDigits(hostPort[colon+1:]) {
			return false
		}
	}
	return canonicalURIComponent(host, true, "")
}
func validCanonicalAbsoluteURI(value string) bool {
	colon := strings.IndexByte(value, ':')
	if colon <= 0 || !canonicalURIScheme(value[:colon]) || !utf8.ValidString(value) || strings.Contains(value, "\\") {
		return false
	}
	for index := 0; index < len(value); index++ {
		if value[index] >= utf8.RuneSelf || value[index] < 0x20 || value[index] == 0x7f || !canonicalURICharacter(value[index]) {
			return false
		}
		if value[index] == '%' {
			if index+2 >= len(value) || !canonicalURIHex(value[index+1]) || !canonicalURIHex(value[index+2]) {
				return false
			}
			index += 2
		}
	}
	remainder := value[colon+1:]
	if strings.Count(remainder, "#") > 1 {
		return false
	}
	hierarchicalAndQuery, fragment, hasFragment := strings.Cut(remainder, "#")
	if hasFragment && !canonicalURIComponent(fragment, true, "/?:@") {
		return false
	}
	hierarchical, query, hasQuery := strings.Cut(hierarchicalAndQuery, "?")
	if hasQuery && !canonicalURIComponent(query, true, "/?:@") {
		return false
	}
	if strings.HasPrefix(hierarchical, "//") {
		authorityAndPath := hierarchical[2:]
		pathStart := strings.IndexByte(authorityAndPath, '/')
		authority, path := authorityAndPath, ""
		if pathStart >= 0 {
			authority, path = authorityAndPath[:pathStart], authorityAndPath[pathStart:]
		}
		return canonicalURIAuthority(authority) && canonicalURIComponent(path, true, "/:@")
	}
	return canonicalURIComponent(hierarchical, true, "/:@")
}

func validCanonicalStringFormat(format, value string) bool {
	switch format {
	case "hostname":
		return validCanonicalHostname(value)
	case "email":
		match := regexp.MustCompile("^[A-Za-z0-9!#$%&'*+/=?^_\\x60{|}~-]+(?:\\.[A-Za-z0-9!#$%&'*+/=?^_\\x60{|}~-]+)*@([A-Za-z0-9.-]+)$").FindStringSubmatch(value)
		return match != nil && validCanonicalHostname(strings.ToLower(match[1]))
	case "ipv4":
		address, err := netip.ParseAddr(value)
		return err == nil && address.Is4() && address.String() == value
	case "ipv6":
		address, err := netip.ParseAddr(value)
		return err == nil && address.Is6() && address.Zone() == "" && address.String() == value
	case "cidr":
		prefix, err := netip.ParsePrefix(value)
		return err == nil && prefix == prefix.Masked() && prefix.String() == value
	case "uri":
		return validCanonicalAbsoluteURI(value)
	}
	return false
}

func validateQueryParameterConsistency(path string, object map[string]any) error {
	valueType, _ := object["value_type"].(string)
	_, hasEnum := object["enum_values"]
	reserved, _ := object["reserved_enum_values"].([]any)
	_, hasFormat := object["format"]
	_, hasMin := object["min"]
	_, hasMax := object["max"]
	_, hasMinLength := object["min_length"]
	_, hasMaxLength := object["max_length"]
	if valueType == "enum" {
		values, ok := object["enum_values"].([]any)
		if !ok || len(values) == 0 {
			return fmt.Errorf("%s enum requires non-empty enum_values", path)
		}
		for _, raw := range append(append([]any{}, values...), reserved...) {
			if text, ok := raw.(string); !ok || text == "" {
				return fmt.Errorf("%s enum values must be non-empty strings", path)
			}
		}
	} else if hasEnum || len(reserved) != 0 {
		return fmt.Errorf("%s enum values are forbidden for %s", path, valueType)
	}
	if hasFormat && valueType != "string" {
		return fmt.Errorf("%s format is only valid for string parameters", path)
	}
	if (hasMin || hasMax) && valueType != "integer" && valueType != "number" {
		return fmt.Errorf("%s numeric bounds are incompatible with %s", path, valueType)
	}
	if (hasMinLength || hasMaxLength) && valueType != "string" {
		return fmt.Errorf("%s length bounds are only valid for string parameters", path)
	}
	if valueType == "integer" {
		for _, property := range []string{"min", "max"} {
			if raw, ok := object[property].(string); ok {
				value, err := strconv.ParseInt(raw, 10, 64)
				if err != nil || value < -9007199254740991 || value > 9007199254740991 {
					return fmt.Errorf("%s.%s must be a safe integer bound", path, property)
				}
			}
		}
	}
	defaultValue, hasDefault := object["default"].(map[string]any)
	if !hasDefault {
		return nil
	}
	if defaultValue["kind"] != valueType {
		return fmt.Errorf("%s default type does not match value_type", path)
	}
	if valueType == "enum" {
		text, _ := defaultValue["string_value"].(string)
		active := false
		for _, raw := range object["enum_values"].([]any) {
			if raw == text {
				active = true
			}
		}
		if !active {
			return fmt.Errorf("%s enum default is not an active enum value", path)
		}
	}
	if valueType == "string" {
		text, _ := defaultValue["string_value"].(string)
		length := int64(utf8.RuneCountInString(text))
		if raw, ok := object["min_length"].(string); ok {
			minimum, _ := strconv.ParseInt(raw, 10, 64)
			if length < minimum {
				return fmt.Errorf("%s default is shorter than min_length", path)
			}
		}
		if raw, ok := object["max_length"].(string); ok {
			maximum, _ := strconv.ParseInt(raw, 10, 64)
			if length > maximum {
				return fmt.Errorf("%s default is longer than max_length", path)
			}
		}
		if format, ok := object["format"].(string); ok && !validCanonicalStringFormat(format, text) {
			return fmt.Errorf("%s default does not satisfy its canonical string format", path)
		}
	}
	if valueType == "integer" || valueType == "number" {
		property := "number_value"
		if valueType == "integer" {
			property = "integer_value"
		}
		text, _ := defaultValue[property].(string)
		number, err := strconv.ParseFloat(text, 64)
		if err != nil {
			return fmt.Errorf("%s has an invalid numeric default", path)
		}
		if raw, ok := object["min"].(string); ok {
			minimum, _ := strconv.ParseFloat(raw, 64)
			if number < minimum {
				return fmt.Errorf("%s default is below min", path)
			}
		}
		if raw, ok := object["max"].(string); ok {
			maximum, _ := strconv.ParseFloat(raw, 64)
			if number > maximum {
				return fmt.Errorf("%s default is above max", path)
			}
		}
	}
	return nil
}

func predicateHasState(raw any) bool {
	object, ok := raw.(map[string]any)
	if !ok {
		return false
	}
	if object["kind"] == "state" {
		return true
	}
	if child, ok := object["child"]; ok && predicateHasState(child) {
		return true
	}
	if predicate, ok := object["predicate"]; ok && predicateHasState(predicate) {
		return true
	}
	if children, ok := object["children"].([]any); ok {
		for _, child := range children {
			if predicateHasState(child) {
				return true
			}
		}
	}
	return false
}

func contextFieldOperand(field, context string) (recipeOperand, bool) {
	switch field {
	case "id", "display_name", "description":
		return recipeOperand{kind: "scalar", scalarType: "string"}, true
	case "tags":
		return recipeOperand{kind: "string_set"}, true
	case "layer":
		if context == "entity" {
			return recipeOperand{kind: "address", addressKind: "layer"}, true
		}
	case "from", "to":
		if context == "relation" {
			return recipeOperand{kind: "address", addressKind: "entity"}, true
		}
	}
	switch field {
	case "address":
		if context == "entity" {
			return recipeOperand{kind: "address", addressKind: "entity"}, true
		}
		if context == "relation" {
			return recipeOperand{kind: "address", addressKind: "relation"}, true
		}
	case "type":
		if context == "entity" {
			return recipeOperand{kind: "address", addressKind: "entity_type"}, true
		}
		if context == "relation" {
			return recipeOperand{kind: "address", addressKind: "relation_type"}, true
		}
	}
	return recipeOperand{}, false
}

type queryDependencySets struct {
	layer, entityType, relationType, entity, relation, column, parameter map[string]bool
	state                                                                map[string]map[string]any
}

func newQueryDependencySets() queryDependencySets {
	return queryDependencySets{map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]map[string]any{}}
}

func (sets *queryDependencySets) addAddress(kind, address string) bool {
	target := map[string]map[string]bool{"layer": sets.layer, "entity_type": sets.entityType, "relation_type": sets.relationType, "entity": sets.entity, "relation": sets.relation, "entity_type_column": sets.column, "relation_type_column": sets.column, "query_parameter": sets.parameter}[kind]
	if target == nil {
		return false
	}
	target[address] = true
	return true
}

func validateQueryPredicateTree(raw any, context, queryAddress string, parameters map[string]string, sets *queryDependencySets) bool {
	object, ok := raw.(map[string]any)
	if !ok {
		return false
	}
	kind, _ := object["kind"].(string)
	switch kind {
	case "all", "any":
		children, ok := object["children"].([]any)
		if !ok {
			return false
		}
		for _, child := range children {
			if !validateQueryPredicateTree(child, context, queryAddress, parameters, sets) {
				return false
			}
		}
		return true
	case "not":
		return validateQueryPredicateTree(object["child"], context, queryAddress, parameters, sets)
	case "rows":
		types, ok := object["type_addresses"].([]any)
		if !ok {
			return false
		}
		expectedKind, rowContext := "entity_type", "entity_row"
		if context == "relation" {
			expectedKind, rowContext = "relation_type", "relation_row"
		}
		for _, rawAddress := range types {
			address, ok := rawAddress.(string)
			actual, _, valid := stableAddressSubject(address)
			if !ok || !valid || actual != expectedKind {
				return false
			}
			sets.addAddress(actual, address)
		}
		return validateQueryPredicateTree(object["predicate"], rowContext, queryAddress, parameters, sets)
	case "field":
		field, _ := object["field"].(string)
		expected, valid := contextFieldOperand(field, context)
		operand, operandOK := parseRecipeOperand(object["operand_type"])
		if !valid || !operandOK || operand != expected {
			return false
		}
	case "cell":
		if context != "entity_row" && context != "relation_row" {
			return false
		}
		addresses, ok := object["column_addresses"].([]any)
		if !ok || len(addresses) == 0 {
			return false
		}
		expectedKind := "entity_type_column"
		if context == "relation_row" {
			expectedKind = "relation_type_column"
		}
		for _, rawAddress := range addresses {
			address, ok := rawAddress.(string)
			actual, _, valid := stableAddressSubject(address)
			if !ok || !valid || actual != expectedKind {
				return false
			}
			sets.column[address] = true
		}
	case "state":
		field, _ := object["field_path"].(string)
		valueType := stateFieldValueType(field)
		operand, operandOK := parseRecipeOperand(object["operand_type"])
		if !operandOK || operand != (recipeOperand{kind: "scalar", scalarType: valueType}) {
			return false
		}
		key := context + "\x00" + field
		sets.state[key] = map[string]any{"subject_kind": context, "field_path": field, "value_type": valueType}
	default:
		return false
	}
	operand, _ := parseRecipeOperand(object["operand_type"])
	value, hasValue := object["value"].(map[string]any)
	if hasValue {
		if value["kind"] == "parameter" {
			address, ok := value["parameter_address"].(string)
			actualKind, owner, valid := stableAddressSubject(address)
			expectedType := operand.scalarType
			if operand.kind == "string_set" {
				expectedType = "string"
			}
			if !ok || !valid || actualKind != "query_parameter" || owner != queryAddress || parameters[address] != expectedType {
				return false
			}
			sets.parameter[address] = true
		}
		for _, property := range []string{"address_value"} {
			if address, ok := value[property].(string); ok {
				actual, _, valid := stableAddressSubject(address)
				if !valid || !sets.addAddress(actual, address) {
					return false
				}
			}
		}
		if values, ok := value["address_values"].([]any); ok {
			for _, rawAddress := range values {
				address, ok := rawAddress.(string)
				actual, _, valid := stableAddressSubject(address)
				if !ok || !valid || !sets.addAddress(actual, address) {
					return false
				}
			}
		}
	}
	return true
}

func dependencyArrayEquals(raw any, expected map[string]bool) bool {
	values, ok := raw.([]any)
	if !ok || len(values) != len(expected) {
		return false
	}
	for _, rawValue := range values {
		value, ok := rawValue.(string)
		if !ok || !expected[value] {
			return false
		}
	}
	return true
}

func validateQueryRecipeConsistency(path string, object map[string]any) error {
	queryAddress, _ := object["address"].(string)
	parameters := map[string]string{}
	if values, ok := object["parameters"].([]any); ok {
		for _, raw := range values {
			value, ok := raw.(map[string]any)
			address, addressOK := value["address"].(string)
			valueType, typeOK := value["value_type"].(string)
			if !ok || !addressOK || !typeOK {
				return fmt.Errorf("%s has an invalid parameter", path)
			}
			parameters[address] = valueType
		}
	}
	sets := newQueryDependencySets()
	selectValue, _ := object["select"].(map[string]any)
	for property, kind := range map[string]string{"layer_addresses": "layer", "entity_type_addresses": "entity_type", "relation_type_addresses": "relation_type", "root_addresses": "entity"} {
		if values, ok := selectValue[property].([]any); ok {
			for _, raw := range values {
				address, ok := raw.(string)
				if !ok || !sets.addAddress(kind, address) {
					return fmt.Errorf("%s has an invalid select dependency", path)
				}
			}
		}
	}
	if traversal, ok := object["traverse"].(map[string]any); ok {
		if values, ok := traversal["relation_type_addresses"].([]any); ok {
			for _, raw := range values {
				address, ok := raw.(string)
				if !ok {
					return fmt.Errorf("%s has an invalid traversal dependency", path)
				}
				sets.relationType[address] = true
			}
		}
	}
	where, whereOK := object["where"].(map[string]any)
	relationWhere, relationOK := object["relation_where"].(map[string]any)
	if !whereOK || !relationOK || !validateQueryPredicateTree(where, "entity", queryAddress, parameters, &sets) || !validateQueryPredicateTree(relationWhere, "relation", queryAddress, parameters, &sets) {
		return fmt.Errorf("%s contains an invalid typed predicate tree", path)
	}
	hasState := len(sets.state) != 0
	stateInput, _ := object["state_input"].(string)
	if hasState != (stateInput == "optional" || stateInput == "required") {
		return fmt.Errorf("%s state_input and state predicates are inconsistent", path)
	}
	dependencies, ok := object["dependencies"].(map[string]any)
	if !ok {
		return fmt.Errorf("%s lacks dependency authority", path)
	}
	for property, expected := range map[string]map[string]bool{"layer_addresses": sets.layer, "entity_type_addresses": sets.entityType, "relation_type_addresses": sets.relationType, "entity_addresses": sets.entity, "relation_addresses": sets.relation, "column_addresses": sets.column, "parameter_addresses": sets.parameter} {
		if !dependencyArrayEquals(dependencies[property], expected) {
			return fmt.Errorf("%s.dependencies.%s is not the exact predicate/select closure", path, property)
		}
	}
	stateReads, ok := dependencies["state_reads"].([]any)
	if !ok || len(stateReads) != len(sets.state) {
		return fmt.Errorf("%s.dependencies.state_reads is not the exact state-read closure", path)
	}
	for _, raw := range stateReads {
		value, ok := raw.(map[string]any)
		if !ok || sets.state[fmt.Sprint(value["subject_kind"])+"\x00"+fmt.Sprint(value["field_path"])] == nil {
			return fmt.Errorf("%s.dependencies.state_reads is not the exact state-read closure", path)
		}
	}
	return nil
}

func stateFieldValueType(path string) string {
	switch path {
	case "system.created_at", "system.updated_at", "provenance.observed_at", "provenance.verified_at", "provenance.stale_after":
		return "datetime"
	case "system.created_by.kind", "system.updated_by.kind", "provenance.source.kind", "provenance.verified_by.kind":
		return "enum"
	case "provenance.confidence":
		return "number"
	default:
		return "string"
	}
}

func validateStateReadConsistency(path string, object map[string]any) error {
	field, _ := object["field_path"].(string)
	valueType, _ := object["value_type"].(string)
	if valueType != stateFieldValueType(field) {
		return fmt.Errorf("%s value_type does not match the state-field registry", path)
	}
	return nil
}

func validateStateReadOrder(path string, values []any) error {
	subjectRanks := map[string]int{"entity": 0, "relation": 1, "entity_row": 2, "relation_row": 3}
	fieldRanks := map[string]int{
		"system.created_at": 0, "system.updated_at": 1, "system.created_by.kind": 2, "system.created_by.id": 3,
		"system.created_by.display_name": 4, "system.updated_by.kind": 5, "system.updated_by.id": 6,
		"system.updated_by.display_name": 7, "system.created_revision": 8, "system.updated_revision": 9,
		"provenance.source.kind": 10, "provenance.source.label": 11, "provenance.source.uri": 12,
		"provenance.source.external_id": 13, "provenance.observed_at": 14, "provenance.verified_at": 15,
		"provenance.stale_after": 16, "provenance.verified_by.kind": 17, "provenance.verified_by.id": 18,
		"provenance.verified_by.display_name": 19, "provenance.confidence": 20,
	}
	previous := -1
	for _, raw := range values {
		value, ok := raw.(map[string]any)
		if !ok {
			return fmt.Errorf("%s contains a non-object state read", path)
		}
		subject, subjectOK := value["subject_kind"].(string)
		field, fieldOK := value["field_path"].(string)
		subjectRank, rankedSubject := subjectRanks[subject]
		fieldRank, rankedField := fieldRanks[field]
		if !subjectOK || !fieldOK || !rankedSubject || !rankedField || value["value_type"] != stateFieldValueType(field) {
			return fmt.Errorf("%s contains an invalid state read", path)
		}
		rank := subjectRank*len(fieldRanks) + fieldRank
		if rank <= previous {
			return fmt.Errorf("%s is not in strict canonical state-read order", path)
		}
		previous = rank
	}
	return nil
}

func stableAddressSubject(value string) (string, string, bool) {
	parts := strings.Split(value, ":")
	if len(parts) < 3 || parts[0] != "ldl" {
		return "", "", false
	}
	start, rootKind := 3, "project"
	if parts[1] == "pack" {
		if len(parts) < 4 {
			return "", "", false
		}
		start, rootKind = 4, "pack"
	} else if parts[1] != "project" {
		return "", "", false
	}
	if len(parts) == start {
		return rootKind, "", true
	}
	if (len(parts)-start)%2 != 0 {
		return "", "", false
	}
	last := parts[len(parts)-2]
	parent := ""
	if len(parts) >= start+2 {
		parent = strings.Join(parts[:len(parts)-2], ":")
	}
	kind := map[string]string{"entity-type": "entity_type", "relation-type": "relation_type", "layer": "layer", "entity": "entity", "relation": "relation", "query": "query", "view": "view", "reference": "reference", "parameter": "query_parameter", "table-column": "view_table_column", "export": "view_export"}[last]
	if last == "row" {
		if len(parts) < start+4 {
			return "", "", false
		}
		switch parts[len(parts)-4] {
		case "entity":
			kind = "entity_row"
		case "relation":
			kind = "relation_row"
		}
	}
	if last == "column" || last == "constraint" {
		if len(parts) < start+4 {
			return "", "", false
		}
		prefix := map[string]string{"entity-type": "entity_type", "relation-type": "relation_type"}[parts[len(parts)-4]]
		if prefix != "" {
			kind = prefix + "_" + last
		}
	}
	if kind == "" {
		return "", "", false
	}
	return kind, parent, true
}

func validateStableAddressRoles(path string, object map[string]any, rules []any) error {
	for _, rawRule := range rules {
		rule, ok := rawRule.(map[string]any)
		if !ok {
			return fmt.Errorf("%s has an invalid stable-address role rule", path)
		}
		kindProperty, _ := rule["kind"].(string)
		expectedKind, ok := object[kindProperty].(string)
		if !ok {
			return fmt.Errorf("%s.%s must name a subject kind", path, kindProperty)
		}
		var values []string
		if property, _ := rule["address"].(string); property != "" {
			value, ok := object[property].(string)
			if !ok {
				return fmt.Errorf("%s.%s must be a StableAddress", path, property)
			}
			values = []string{value}
		} else {
			property, _ := rule["addresses"].(string)
			rawValues, ok := object[property].([]any)
			if !ok {
				return fmt.Errorf("%s.%s must be StableAddresses", path, property)
			}
			for _, raw := range rawValues {
				value, ok := raw.(string)
				if !ok {
					return fmt.Errorf("%s.%s contains a non-address", path, property)
				}
				values = append(values, value)
			}
		}
		ownerProperty, _ := rule["owner"].(string)
		policy, _ := rule["owner_policy"].(string)
		owner, ownerPresent := object[ownerProperty].(string)
		for _, value := range values {
			actualKind, actualOwner, valid := stableAddressSubject(value)
			if !valid || actualKind != expectedKind {
				return fmt.Errorf("%s address %q does not match kind %q", path, value, expectedKind)
			}
			switch policy {
			case "children":
				if !ownerPresent || actualOwner != owner {
					return fmt.Errorf("%s address %q is not a direct child of %q", path, value, owner)
				}
			case "exact":
				if (actualOwner != "") != ownerPresent || ownerPresent && actualOwner != owner {
					return fmt.Errorf("%s has an inexact owner for %q", path, value)
				}
			case "if_present":
				if ownerPresent && actualOwner != owner {
					return fmt.Errorf("%s has a wrong owner for %q", path, value)
				}
			case "row_only":
				required := actualKind == "entity_row" || actualKind == "relation_row"
				if required != ownerPresent || ownerPresent && actualOwner != owner {
					return fmt.Errorf("%s has an invalid row owner for %q", path, value)
				}
			case "":
			default:
				return fmt.Errorf("%s has an unknown stable-address owner policy", path)
			}
		}
	}
	return nil
}

type recipeOperand struct{ kind, scalarType, addressKind string }

func parseRecipeOperand(raw any) (recipeOperand, bool) {
	value, ok := raw.(map[string]any)
	if !ok {
		return recipeOperand{}, false
	}
	operand := recipeOperand{}
	operand.kind, _ = value["kind"].(string)
	operand.scalarType, _ = value["scalar_type"].(string)
	operand.addressKind, _ = value["address_kind"].(string)
	switch operand.kind {
	case "scalar":
		return operand, operand.scalarType != ""
	case "address":
		return operand, operand.addressKind != ""
	case "string_set":
		return operand, true
	}
	return recipeOperand{}, false
}

func equalRecipeOperand(left, right recipeOperand) bool { return left == right }

func fieldRecipeOperand(field string) (recipeOperand, bool) {
	switch field {
	case "id", "display_name", "description":
		return recipeOperand{kind: "scalar", scalarType: "string"}, true
	case "tags":
		return recipeOperand{kind: "string_set"}, true
	case "layer":
		return recipeOperand{kind: "address", addressKind: "layer"}, true
	case "from", "to":
		return recipeOperand{kind: "address", addressKind: "entity"}, true
	}
	return recipeOperand{}, false
}

func recipeScalarKind(raw any) (string, bool) {
	value, ok := raw.(map[string]any)
	if !ok {
		return "", false
	}
	kind, ok := value["kind"].(string)
	return kind, ok
}

func compareRecipeScalars(left, right map[string]any) int {
	kind, _ := left["kind"].(string)
	switch kind {
	case "boolean":
		a, _ := left["boolean_value"].(bool)
		b, _ := right["boolean_value"].(bool)
		if a == b {
			return 0
		}
		if !a {
			return -1
		}
		return 1
	case "integer":
		a, _ := strconv.ParseInt(fmt.Sprint(left["integer_value"]), 10, 64)
		b, _ := strconv.ParseInt(fmt.Sprint(right["integer_value"]), 10, 64)
		if a < b {
			return -1
		}
		if a > b {
			return 1
		}
		return 0
	case "number":
		a, _ := strconv.ParseFloat(fmt.Sprint(left["number_value"]), 64)
		b, _ := strconv.ParseFloat(fmt.Sprint(right["number_value"]), 64)
		if a < b {
			return -1
		}
		if a > b {
			return 1
		}
		return 0
	default:
		return strings.Compare(fmt.Sprint(left["string_value"]), fmt.Sprint(right["string_value"]))
	}
}

func validateRecipeScalarSet(raw any, scalarType string) bool {
	values, ok := raw.([]any)
	if !ok {
		return false
	}
	for _, rawValue := range values {
		value, ok := rawValue.(map[string]any)
		if !ok || value["kind"] != scalarType {
			return false
		}
	}
	return true
}

func validateRecipePredicateValue(value map[string]any, operator string, operand recipeOperand) bool {
	kind, _ := value["kind"].(string)
	if kind == "parameter" {
		return operator != "in" && operator != "not_in" && (operand.kind == "scalar" || operand.kind == "string_set" && operator == "contains")
	}
	if operator == "in" || operator == "not_in" {
		if operand.kind == "scalar" {
			return kind == "scalar_set" && validateRecipeScalarSet(value["scalar_values"], operand.scalarType)
		}
		if operand.kind == "address" && kind == "address_set" {
			values, ok := value["address_values"].([]any)
			if !ok {
				return false
			}
			for _, raw := range values {
				address, ok := raw.(string)
				actual, _, valid := stableAddressSubject(address)
				if !ok || !valid || actual != operand.addressKind {
					return false
				}
			}
			return true
		}
		return false
	}
	if operand.kind == "string_set" {
		if operator == "eq" || operator == "ne" {
			return kind == "scalar_set" && validateRecipeScalarSet(value["scalar_values"], "string")
		}
		return operator == "contains" && kind == "scalar" && value["scalar_value"] != nil && func() bool { scalar, ok := recipeScalarKind(value["scalar_value"]); return ok && scalar == "string" }()
	}
	if operand.kind == "scalar" {
		scalar, ok := recipeScalarKind(value["scalar_value"])
		return kind == "scalar" && ok && scalar == operand.scalarType
	}
	if operand.kind == "address" && kind == "address" {
		address, ok := value["address_value"].(string)
		actual, _, valid := stableAddressSubject(address)
		return ok && valid && actual == operand.addressKind
	}
	return false
}

func validateRecipePredicateConsistency(path string, object map[string]any, predicateKind string) error {
	kind, _ := object["kind"].(string)
	if kind == "all" || kind == "any" {
		children, _ := object["children"].([]any)
		for index, raw := range children {
			child, ok := raw.(map[string]any)
			if !ok {
				return fmt.Errorf("%s.children[%d] is invalid", path, index)
			}
			if err := validateRecipePredicateConsistency(fmt.Sprintf("%s.children[%d]", path, index), child, predicateKind); err != nil {
				return err
			}
		}
		return nil
	}
	if kind == "not" {
		child, _ := object["child"].(map[string]any)
		return validateRecipePredicateConsistency(path+".child", child, predicateKind)
	}
	if kind == "rows" {
		child, _ := object["predicate"].(map[string]any)
		return validateRecipePredicateConsistency(path+".predicate", child, "row")
	}
	if kind != "field" && kind != "cell" && kind != "state" {
		return nil
	}
	operand, ok := parseRecipeOperand(object["operand_type"])
	if !ok {
		return fmt.Errorf("%s has an invalid operand_type", path)
	}
	if kind == "field" {
		if expected, known := fieldRecipeOperand(fmt.Sprint(object["field"])); known && !equalRecipeOperand(operand, expected) {
			return fmt.Errorf("%s operand_type does not match its field", path)
		}
	}
	if kind == "state" {
		expected := recipeOperand{kind: "scalar", scalarType: stateFieldValueType(fmt.Sprint(object["field_path"]))}
		if !equalRecipeOperand(operand, expected) {
			return fmt.Errorf("%s operand_type does not match its state field", path)
		}
	}
	operator, _ := object["operator"].(string)
	compatible := operator == "eq" || operator == "ne" || operator == "exists" || operator == "missing"
	if operator == "lt" || operator == "lte" || operator == "gt" || operator == "gte" {
		compatible = operand.kind == "scalar" && map[string]bool{"integer": true, "number": true, "date": true, "datetime": true}[operand.scalarType]
	}
	if operator == "in" || operator == "not_in" {
		compatible = operand.kind == "scalar" || operand.kind == "address"
	}
	if operator == "contains" {
		compatible = operand.kind == "string_set" || operand.kind == "scalar" && operand.scalarType == "string"
	}
	if operator == "starts_with" || operator == "ends_with" {
		compatible = operand.kind == "scalar" && operand.scalarType == "string"
	}
	if !compatible {
		return fmt.Errorf("%s operator is incompatible with operand_type", path)
	}
	if operator != "exists" && operator != "missing" {
		value, ok := object["value"].(map[string]any)
		if !ok || !validateRecipePredicateValue(value, operator, operand) {
			return fmt.Errorf("%s value is incompatible with operand_type and operator", path)
		}
	}
	return nil
}

func validateViewProjectionConsistency(path string, object map[string]any, kind string) error {
	distinct := func(left, right string) bool {
		a, aOK := object[left].(string)
		b, bOK := object[right].(string)
		return aOK && bOK && a != b
	}
	if kind != "composed" {
		pairs := map[string][2]string{"diagram": {"source_endpoint", "target_endpoint"}, "flow": {"source_endpoint", "target_endpoint"}, "matrix": {"row_endpoint", "column_endpoint"}, "tree": {"parent_endpoint", "child_endpoint"}}
		pair := pairs[kind]
		if !distinct(pair[0], pair[1]) {
			return fmt.Errorf("%s effective %s endpoints must be present and distinct", path, kind)
		}
		return nil
	}
	mode, _ := object["mode"].(string)
	present := func(name string) bool { _, ok := object[name]; return ok }
	switch mode {
	case "nest":
		if !distinct("parent_endpoint", "child_endpoint") || present("overlay_endpoint") || present("target_endpoint") || present("badge_endpoint") {
			return fmt.Errorf("%s has invalid nest endpoints", path)
		}
	case "overlay":
		if !distinct("overlay_endpoint", "target_endpoint") || present("parent_endpoint") || present("child_endpoint") || present("badge_endpoint") {
			return fmt.Errorf("%s has invalid overlay endpoints", path)
		}
	case "badge":
		if !distinct("badge_endpoint", "target_endpoint") || present("parent_endpoint") || present("child_endpoint") || present("overlay_endpoint") {
			return fmt.Errorf("%s has invalid badge endpoints", path)
		}
	case "edge", "hide":
		if present("parent_endpoint") || present("child_endpoint") || present("overlay_endpoint") || present("target_endpoint") || present("badge_endpoint") {
			return fmt.Errorf("%s endpoint fields are forbidden for %s", path, mode)
		}
	}
	return nil
}

func fidelityRank(value string) int {
	return map[string]int{"lossy": 0, "visual_only": 1, "traceable_summary": 2, "lossless": 3}[value]
}
func statePolicyRank(value string) int {
	return map[string]int{"none": 0, "optional": 1, "required": 2}[value]
}

func validateExportRecipeConsistency(path string, object map[string]any) error {
	format, formatOK := object["format"].(string)
	options, optionsOK := object["options"].(map[string]any)
	profile, profileOK := object["exporter_profile"].(map[string]any)
	extension, extensionOK := object["extension"].(string)
	filename, filenameOK := object["filename"].(string)
	if !formatOK || !optionsOK || !profileOK || !extensionOK || !filenameOK || options["kind"] != format || profile["format"] != format {
		return fmt.Errorf("%s has inconsistent Export format authority", path)
	}
	expected, exists := map[string]string{"json": ".json", "yaml": ".yaml", "svg": ".svg", "png": ".png", "pdf": ".pdf", "html": ".html", "csv": ".csv", "tsv": ".tsv", "xlsx": ".xlsx", "markdown": ".md", "pptx": ".pptx", "docx": ".docx", "mermaid": ".mmd", "bpmn": ".bpmn", "drawio": ".drawio"}[format]
	if !exists || extension != expected {
		return fmt.Errorf("%s extension does not match Export format", path)
	}
	stem := strings.TrimSuffix(filename, extension)
	if filename == "" || filename == "." || filename == ".." || strings.ContainsAny(filename, "/\\\x00") || !strings.HasSuffix(filename, extension) || stem == "" {
		return fmt.Errorf("%s filename is not a canonical Export basename", path)
	}
	native, _ := object["native_maximum_fidelity"].(string)
	effective, _ := object["effective_maximum_fidelity"].(string)
	fidelity, _ := object["fidelity"].(string)
	basis, _ := object["fidelity_basis"].(string)
	sourceRefs, _ := object["source_refs"].(bool)
	fixedMaximum := map[string]string{"json": "lossless", "yaml": "lossless", "xlsx": "traceable_summary", "html": "traceable_summary", "svg": "visual_only", "png": "visual_only", "pdf": "visual_only", "pptx": "visual_only", "docx": "visual_only", "drawio": "visual_only", "bpmn": "lossy"}[format]
	if fixedMaximum != "" && native != fixedMaximum {
		return fmt.Errorf("%s does not state the exact format-intrinsic native fidelity", path)
	}
	if format == "csv" || format == "tsv" {
		expected := "lossy"
		if options["bundle"] == true && options["header"] == true && options["source_manifest"] == true {
			expected = "traceable_summary"
		}
		if native != expected {
			return fmt.Errorf("%s does not state the exact delimited native fidelity", path)
		}
	}
	if format == "markdown" && native != "lossy" && native != "traceable_summary" || format == "mermaid" && native != "lossy" && native != "traceable_summary" {
		return fmt.Errorf("%s has an impossible context-dependent native fidelity", path)
	}
	embedded := format == "xlsx" && options["view_data_json"] == true && options["hidden_ids"] == true
	if embedded {
		if basis != "embedded_viewdata" || effective != "lossless" {
			return fmt.Errorf("%s has inconsistent embedded ViewData fidelity", path)
		}
	} else if basis != "native" || effective != native {
		return fmt.Errorf("%s has inconsistent native fidelity basis", path)
	}
	if fidelityRank(fidelity) > fidelityRank(effective) {
		return fmt.Errorf("%s requested fidelity exceeds effective capability", path)
	}
	if (fidelity == "lossless" || fidelity == "traceable_summary" || format == "json" || format == "yaml") && !sourceRefs {
		return fmt.Errorf("%s fidelity requires source_refs", path)
	}
	embeddedManifest := format == "json" || format == "yaml" || format == "xlsx" && options["view_data_json"] == true
	explicitManifest := (format == "csv" || format == "tsv" || format == "markdown" || format == "mermaid" || format == "bpmn" || format == "drawio") && options["source_manifest"] == true
	minimumManifest := explicitManifest || sourceRefs && !embeddedManifest
	requiresManifest, _ := object["requires_source_manifest"].(bool)
	if minimumManifest && !requiresManifest {
		return fmt.Errorf("%s omits a required source manifest", path)
	}
	return nil
}

func viewTableValueMatches(column map[string]any, kind, scalar string, enumValues []string) bool {
	value, ok := column["value_type"].(map[string]any)
	if !ok || value["kind"] != kind {
		return false
	}
	if kind == "scalar" && value["scalar_type"] != scalar {
		return false
	}
	if enumValues != nil {
		values, ok := value["enum_values"].([]any)
		if !ok || len(values) != len(enumValues) {
			return false
		}
		for index := range values {
			if values[index] != enumValues[index] {
				return false
			}
		}
	}
	if kind == "scalar" {
		_, hasEnum := value["enum_values"]
		_, hasFormat := value["format"]
		if scalar == "enum" {
			values, ok := value["enum_values"].([]any)
			if enumValues == nil && (!hasEnum || !ok || len(values) == 0) {
				return false
			}
		} else if hasEnum {
			return false
		}
		if hasFormat && scalar != "string" {
			return false
		}
	}
	return true
}

func stateEnumValues(field string) []string {
	switch field {
	case "system.created_by.kind", "system.updated_by.kind", "provenance.verified_by.kind":
		return []string{"user", "agent", "service_account", "anonymous"}
	case "provenance.source.kind":
		return []string{"manual", "import", "api", "agent", "external_system"}
	default:
		return nil
	}
}

func containsStateRead(values []any, expected map[string]any) bool {
	for _, raw := range values {
		value, ok := raw.(map[string]any)
		if ok && value["subject_kind"] == expected["subject_kind"] && value["field_path"] == expected["field_path"] && value["value_type"] == expected["value_type"] {
			return true
		}
	}
	return false
}

type viewDependencySets struct{ query, parameter, layer, entityType, relationType, entity, relation, column map[string]bool }

func newViewDependencySets() viewDependencySets {
	return viewDependencySets{map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]bool{}, map[string]bool{}}
}

func (sets *viewDependencySets) add(address string) {
	kind, _, valid := stableAddressSubject(address)
	if !valid {
		return
	}
	target := map[string]map[string]bool{"query": sets.query, "query_parameter": sets.parameter, "layer": sets.layer, "entity_type": sets.entityType, "relation_type": sets.relationType, "entity": sets.entity, "relation": sets.relation, "entity_type_column": sets.column, "relation_type_column": sets.column}[kind]
	if target != nil {
		target[address] = true
	}
}

func addViewDependencyValues(raw any, sets *viewDependencySets) {
	switch value := raw.(type) {
	case string:
		sets.add(value)
	case []any:
		for _, item := range value {
			if address, ok := item.(string); ok {
				sets.add(address)
			}
		}
	}
}

func collectViewDependencyAddresses(raw any, sets *viewDependencySets) {
	switch value := raw.(type) {
	case []any:
		for _, item := range value {
			collectViewDependencyAddresses(item, sets)
		}
	case map[string]any:
		for property, item := range value {
			switch property {
			case "arguments":
				if arguments, ok := item.(map[string]any); ok {
					for address := range arguments {
						sets.add(address)
					}
				}
			case "query_address", "entity_address", "relation_address", "layer_address", "parameter_address",
				"branch_value_column_address",
				"layer_addresses", "entity_type_addresses", "relation_type_addresses", "entity_addresses", "relation_addresses",
				"column_addresses", "lane_column_addresses", "attribute_column_addresses":
				addViewDependencyValues(item, sets)
			default:
				collectViewDependencyAddresses(item, sets)
			}
		}
	}
}

func dependencyContainsAll(raw any, expected map[string]bool) bool {
	values, ok := raw.([]any)
	if !ok {
		return false
	}
	actual := map[string]bool{}
	for _, item := range values {
		value, ok := item.(string)
		if !ok {
			return false
		}
		actual[value] = true
	}
	for value := range expected {
		if !actual[value] {
			return false
		}
	}
	return true
}

func validateLocallyDerivableViewDependencies(object map[string]any) bool {
	dependencies, dependenciesOK := object["dependencies"].(map[string]any)
	source, sourceOK := object["source"].(map[string]any)
	shape, shapeOK := object["shape"].(map[string]any)
	overrides, overridesOK := object["relation_projection_overrides"].(map[string]any)
	if !dependenciesOK || !sourceOK || !shapeOK || !overridesOK {
		return false
	}
	sets := newViewDependencySets()
	collectViewDependencyAddresses(source, &sets)
	collectViewDependencyAddresses(shape, &sets)
	for address, override := range overrides {
		sets.add(address)
		collectViewDependencyAddresses(override, &sets)
	}
	if !dependencyArrayEquals(dependencies["query_addresses"], sets.query) {
		return false
	}
	_, hasSourceQuery := source["query_address"].(string)
	checks := []struct {
		property string
		values   map[string]bool
	}{{"parameter_addresses", sets.parameter}, {"layer_addresses", sets.layer}, {"entity_type_addresses", sets.entityType}, {"relation_type_addresses", sets.relationType}, {"entity_addresses", sets.entity}, {"relation_addresses", sets.relation}, {"column_addresses", sets.column}}
	for _, check := range checks {
		if hasSourceQuery {
			if !dependencyContainsAll(dependencies[check.property], check.values) {
				return false
			}
		} else if !dependencyArrayEquals(dependencies[check.property], check.values) {
			return false
		}
	}
	exports, exportsOK := object["exports"].([]any)
	exportAddresses, addressesOK := dependencies["export_addresses"].([]any)
	if !exportsOK || !addressesOK || len(exports) != len(exportAddresses) {
		return false
	}
	for index, raw := range exports {
		export, ok := raw.(map[string]any)
		address, addressOK := export["address"].(string)
		dependency, dependencyOK := exportAddresses[index].(string)
		if !ok || !addressOK || !dependencyOK || address != dependency {
			return false
		}
	}
	return true
}

func validateViewRecipeConsistency(path string, object map[string]any) error {
	address, addressOK := object["address"].(string)
	shape, shapeOK := object["shape"].(map[string]any)
	reservedValues, reservedOK := object["reserved_table_column_ids"].([]any)
	if !addressOK || !shapeOK || !reservedOK {
		return fmt.Errorf("%s has invalid View recipe authority fields", path)
	}
	category, _ := object["category"].(string)
	source, _ := object["source"].(map[string]any)
	sourceKind, _ := source["kind"].(string)
	shapeKind, _ := shape["kind"].(string)
	diffCount := 0
	if category == "diff" {
		diffCount++
	}
	if sourceKind == "diff" {
		diffCount++
	}
	if shapeKind == "diff" {
		diffCount++
	}
	if diffCount != 0 && diffCount != 3 {
		return fmt.Errorf("%s diff category, source, and shape must occur together", path)
	}
	stateInput, _ := object["state_input"].(string)
	stateRequirement, _ := object["state_requirement"].(string)
	if statePolicyRank(stateRequirement) < statePolicyRank(stateInput) {
		return fmt.Errorf("%s state_requirement cannot be weaker than state_input", path)
	}
	if diffCount == 3 && stateRequirement != "none" {
		return fmt.Errorf("%s Diff recipes forbid state requirements", path)
	}
	dependencies, dependenciesOK := object["dependencies"].(map[string]any)
	if !dependenciesOK {
		return fmt.Errorf("%s lacks View dependencies", path)
	}
	stateReads, stateReadsOK := dependencies["state_reads"].([]any)
	if !stateReadsOK {
		return fmt.Errorf("%s lacks View state reads", path)
	}
	var directReads []map[string]any
	if shapeKind == "table" {
		table, tableOK := shape["table"].(map[string]any)
		columns, columnsOK := table["columns"].([]any)
		if !tableOK || !columnsOK {
			return fmt.Errorf("%s has invalid table shape authority", path)
		}
		rowSource, _ := table["row_source"].(string)
		entityRows := rowSource == "entity" || rowSource == "entity_rows"
		if !entityRows && (table["include_entity_id"] == true || table["include_type"] == true || table["include_layer"] == true) {
			return fmt.Errorf("%s fixed Entity columns are forbidden for Relation rows", path)
		}
		if !entityRows {
			if _, present := table["entity_type_addresses"]; present {
				return fmt.Errorf("%s entity type selectors are forbidden for Relation rows", path)
			}
		}
		available := map[string]bool{}
		if table["include_entity_id"] == true {
			available["entity_id"] = true
		}
		if table["include_type"] == true {
			available["entity_type"] = true
		}
		if table["include_layer"] == true {
			available["entity_layer"] = true
		}
		automaticColumns, automaticOK := table["automatic_relation_columns"].([]any)
		if !automaticOK {
			return fmt.Errorf("%s lacks automatic Relation column authority", path)
		}
		if rowSource != "automatic_relations" && len(automaticColumns) != 0 {
			return fmt.Errorf("%s declares automatic Relation columns for a non-automatic row source", path)
		}
		for _, raw := range automaticColumns {
			id, ok := raw.(string)
			if !ok {
				return fmt.Errorf("%s has a non-string automatic Relation column", path)
			}
			available[id] = true
		}
		reserved := map[string]bool{}
		for _, raw := range reservedValues {
			value, ok := raw.(string)
			if !ok {
				return fmt.Errorf("%s has a non-string table reservation", path)
			}
			reserved[value] = true
		}
		for _, raw := range columns {
			column, ok := raw.(map[string]any)
			if !ok {
				return fmt.Errorf("%s has a non-object table column", path)
			}
			columnAddress, addressPresent := column["address"].(string)
			id, idPresent := column["id"].(string)
			if !addressPresent || !idPresent || !hasDirectStableAddressOwner(address, columnAddress) {
				return fmt.Errorf("%s has a table column outside its View owner", path)
			}
			if reserved[id] || available[id] {
				return fmt.Errorf("%s table column ID %q conflicts with reserved or fixed columns", path, id)
			}
			available[id] = true
			columnSource, ok := column["source"].(map[string]any)
			if !ok {
				return fmt.Errorf("%s table column lacks a source", path)
			}
			sourceKind, _ := columnSource["kind"].(string)
			aggregate, _ := column["aggregate"].(string)
			switch sourceKind {
			case "attribute":
				if rowSource != "entity_rows" && rowSource != "relation_rows" {
					return fmt.Errorf("%s attribute source has an incompatible row source", path)
				}
				addresses, ok := columnSource["column_addresses"].([]any)
				if !ok || len(addresses) == 0 {
					return fmt.Errorf("%s attribute source must name Columns", path)
				}
				expectedKind := "entity_type_column"
				if rowSource == "relation_rows" {
					expectedKind = "relation_type_column"
				}
				for _, rawAddress := range addresses {
					address, ok := rawAddress.(string)
					actual, _, valid := stableAddressSubject(address)
					if !ok || !valid || actual != expectedKind {
						return fmt.Errorf("%s attribute source names a wrong-owner Column", path)
					}
				}
			case "relation_endpoint":
				if rowSource != "relation" && rowSource != "relation_rows" {
					return fmt.Errorf("%s relation endpoint requires Relation rows", path)
				}
				field, _ := columnSource["field"].(string)
				if field == "id" || field == "display_name" {
					if !viewTableValueMatches(column, "scalar", "string", nil) {
						return fmt.Errorf("%s relation endpoint value_type is wrong", path)
					}
				} else if !viewTableValueMatches(column, "stable_address", "", nil) {
					return fmt.Errorf("%s relation endpoint value_type is wrong", path)
				}
			case "derived_count":
				if !entityRows || !viewTableValueMatches(column, "scalar", "integer", nil) {
					return fmt.Errorf("%s derived count contract is invalid", path)
				}
			case "field":
				field, _ := columnSource["field"].(string)
				if field == "id" || field == "display_name" || field == "description" {
					if !viewTableValueMatches(column, "scalar", "string", nil) {
						return fmt.Errorf("%s field value_type is wrong", path)
					}
				} else if field == "tags" {
					if !viewTableValueMatches(column, "string_set", "", nil) {
						return fmt.Errorf("%s tag field value_type is wrong", path)
					}
				} else if !viewTableValueMatches(column, "stable_address", "", nil) {
					return fmt.Errorf("%s address field value_type is wrong", path)
				}
			case "state":
				field, _ := columnSource["field_path"].(string)
				valueType := stateFieldValueType(field)
				enumValues := stateEnumValues(field)
				if !viewTableValueMatches(column, "scalar", valueType, enumValues) {
					return fmt.Errorf("%s state column value_type is wrong", path)
				}
				subjects := []string{}
				switch rowSource {
				case "entity":
					subjects = []string{"entity"}
				case "entity_rows":
					subjects = []string{"entity_row"}
				case "relation":
					subjects = []string{"relation"}
				case "relation_rows":
					subjects = []string{"relation_row"}
				case "automatic_relations":
					subjects = []string{"relation", "relation_row"}
				}
				for _, subject := range subjects {
					directReads = append(directReads, map[string]any{"subject_kind": subject, "field_path": field, "value_type": valueType})
				}
			default:
				return fmt.Errorf("%s table column has an unknown source", path)
			}
			if (aggregate == "count" || aggregate == "count_distinct") && !viewTableValueMatches(column, "scalar", "integer", nil) {
				return fmt.Errorf("%s count aggregate has a wrong output type", path)
			}
			if aggregate == "join_unique" && !viewTableValueMatches(column, "scalar", "string", nil) {
				return fmt.Errorf("%s join_unique has a wrong output type", path)
			}
			if aggregate == "min" || aggregate == "max" {
				valueType, ok := column["value_type"].(map[string]any)
				if !ok || valueType["kind"] != "scalar" || !map[string]bool{"integer": true, "number": true, "date": true, "datetime": true, "enum": true}[fmt.Sprint(valueType["scalar_type"])] {
					return fmt.Errorf("%s min/max has an incompatible output type", path)
				}
			}
		}
		if (len(directReads) != 0) != (stateInput == "optional" || stateInput == "required") {
			return fmt.Errorf("%s state_input and direct Table state reads are inconsistent", path)
		}
		if sorts, ok := table["sorts"].([]any); ok {
			for _, raw := range sorts {
				sortValue, _ := raw.(map[string]any)
				id, _ := sortValue["column_id"].(string)
				if !available[id] {
					return fmt.Errorf("%s sort names unavailable column %q", path, id)
				}
			}
		}
		for _, read := range directReads {
			if !containsStateRead(stateReads, read) {
				return fmt.Errorf("%s dependencies omit a direct Table state read", path)
			}
		}
	} else if stateInput != "none" {
		return fmt.Errorf("%s state_input is forbidden without direct Table state reads", path)
	}
	if _, hasSourceQuery := source["query_address"].(string); !hasSourceQuery && len(stateReads) != len(directReads) {
		return fmt.Errorf("%s dependencies contain non-derivable state reads", path)
	}
	exports, _ := object["exports"].([]any)
	for _, raw := range exports {
		export, ok := raw.(map[string]any)
		if !ok || export["view_address"] != address || !validateExportInView(export, category, shapeKind, stateRequirement, diffCount == 3) {
			return fmt.Errorf("%s contains an Export incompatible with its View context", path)
		}
	}
	if !validateLocallyDerivableViewDependencies(object) {
		return fmt.Errorf("%s dependencies omit or misorder locally derivable View dependencies", path)
	}
	return nil
}

func validateExportInView(object map[string]any, category, shape, stateRequirement string, diff bool) bool {
	format, _ := object["format"].(string)
	options, _ := object["options"].(map[string]any)
	if format == "json" || format == "yaml" {
		return object["native_maximum_fidelity"] == "lossless" && object["effective_maximum_fidelity"] == "lossless" && object["fidelity_basis"] == "native" && validateManifestClaim(object, stateRequirement, true) && !(diff && options["state_summary"] == true)
	}
	matrix := map[string]map[string]string{
		"diagram": {"xlsx": "traceable_summary", "html": "traceable_summary", "csv": "traceable_summary", "tsv": "traceable_summary", "svg": "visual_only", "png": "visual_only", "pdf": "visual_only", "pptx": "visual_only", "docx": "visual_only", "drawio": "visual_only", "mermaid": "lossy"},
		"table":   {"xlsx": "traceable_summary", "csv": "traceable_summary", "tsv": "traceable_summary", "html": "traceable_summary", "pdf": "visual_only", "pptx": "visual_only", "docx": "visual_only", "markdown": "lossy"},
		"matrix":  {"xlsx": "traceable_summary", "csv": "traceable_summary", "tsv": "traceable_summary", "html": "traceable_summary", "svg": "visual_only", "png": "visual_only", "pdf": "visual_only", "pptx": "visual_only", "docx": "visual_only"},
		"tree":    {"xlsx": "traceable_summary", "csv": "traceable_summary", "tsv": "traceable_summary", "html": "traceable_summary", "mermaid": "traceable_summary", "svg": "visual_only", "png": "visual_only", "pdf": "visual_only", "pptx": "visual_only", "docx": "visual_only", "drawio": "visual_only"},
		"flow":    {"xlsx": "traceable_summary", "csv": "traceable_summary", "tsv": "traceable_summary", "html": "traceable_summary", "mermaid": "traceable_summary", "bpmn": "lossy", "svg": "visual_only", "png": "visual_only", "pdf": "visual_only", "pptx": "visual_only", "docx": "visual_only", "drawio": "visual_only", "markdown": "lossy"},
		"context": {"csv": "traceable_summary", "tsv": "traceable_summary", "xlsx": "traceable_summary", "html": "traceable_summary", "markdown": "traceable_summary", "pdf": "visual_only", "pptx": "visual_only", "docx": "visual_only"},
		"diff":    {"csv": "traceable_summary", "tsv": "traceable_summary", "xlsx": "traceable_summary", "html": "traceable_summary", "markdown": "traceable_summary", "pdf": "visual_only", "pptx": "visual_only", "docx": "visual_only"},
	}
	native, allowed := matrix[shape][format]
	if !allowed {
		return false
	}
	if format == "csv" || format == "tsv" {
		if options["bundle"] != true || options["header"] != true || options["source_manifest"] != true {
			native = "lossy"
		}
	}
	if (shape == "tree" || shape == "flow") && format == "mermaid" && options["source_manifest"] != true {
		native = "lossy"
	}
	if object["native_maximum_fidelity"] != native {
		return false
	}
	embedded := format == "xlsx" && options["view_data_json"] == true && options["hidden_ids"] == true
	if embedded {
		if object["effective_maximum_fidelity"] != "lossless" || object["fidelity_basis"] != "embedded_viewdata" {
			return false
		}
	} else if object["effective_maximum_fidelity"] != native || object["fidelity_basis"] != "native" {
		return false
	}
	if format == "xlsx" {
		profile, _ := options["profile"].(string)
		compatible := false
		switch profile {
		case "type_workbook":
			compatible = shape == "table"
		case "diagram_workbook", "composed_diagram_workbook", "diagram_inventory_workbook":
			compatible = shape == "diagram"
		case "matrix_workbook":
			compatible = shape == "matrix"
		case "tree_workbook":
			compatible = shape == "tree"
		case "flow_workbook":
			compatible = shape == "flow"
		case "diff_workbook":
			compatible = shape == "diff"
		case "context_workbook":
			compatible = shape == "context"
		case "impact_workbook":
			compatible = category == "impact" && (shape == "diagram" || shape == "table" || shape == "matrix")
		}
		if !compatible {
			return false
		}
	}
	return validateManifestClaim(object, stateRequirement, format == "xlsx" && options["view_data_json"] == true)
}

func validateManifestClaim(object map[string]any, stateRequirement string, embedded bool) bool {
	options, _ := object["options"].(map[string]any)
	sourceRefs, _ := object["source_refs"].(bool)
	explicit := (options["kind"] == "csv" || options["kind"] == "tsv") && options["source_manifest"] == true || (options["kind"] == "markdown" || options["kind"] == "mermaid" || options["kind"] == "bpmn" || options["kind"] == "drawio") && options["source_manifest"] == true
	required := explicit || stateRequirement != "none" || sourceRefs && !embedded
	return object["requires_source_manifest"] == required
}

func validateAddressOwners(path string, object map[string]any, rules []any) error {
	for _, rawRule := range rules {
		rule, _ := rawRule.(map[string]any)
		ownerProperty, _ := rule["owner"].(string)
		childrenProperty, _ := rule["children"].(string)
		selector, _ := rule["selector"].(string)
		rawOwner, ownerPresent := object[ownerProperty]
		if !ownerPresent {
			continue
		}
		owner, ownerOK := rawOwner.(string)
		if !ownerOK {
			return fmt.Errorf("%s.%s must be a StableAddress owner", path, ownerProperty)
		}
		rawChildren, childrenPresent := object[childrenProperty]
		if !childrenPresent {
			continue
		}
		var children []string
		switch selector {
		case "$value":
			child, ok := rawChildren.(string)
			if !ok {
				return fmt.Errorf("%s.%s must be a child StableAddress", path, childrenProperty)
			}
			children = append(children, child)
		case "$propertyNames":
			values, ok := rawChildren.(map[string]any)
			if !ok {
				return fmt.Errorf("%s.%s must be an address-keyed object", path, childrenProperty)
			}
			for child := range values {
				children = append(children, child)
			}
		default:
			values, ok := rawChildren.([]any)
			if !ok {
				return fmt.Errorf("%s.%s must be an array of child records", path, childrenProperty)
			}
			for _, rawChild := range values {
				childObject, ok := rawChild.(map[string]any)
				if !ok {
					return fmt.Errorf("%s.%s contains a non-object child", path, childrenProperty)
				}
				child, ok := childObject[selector].(string)
				if !ok {
					return fmt.Errorf("%s.%s child has no address selector %s", path, childrenProperty, selector)
				}
				children = append(children, child)
			}
		}
		for _, child := range children {
			if !hasDirectStableAddressOwner(owner, child) {
				return fmt.Errorf("%s child address %q is not directly owned by %q", path, child, owner)
			}
		}
	}
	return nil
}

func hasDirectStableAddressOwner(owner, child string) bool {
	parts := strings.Split(child, ":")
	return len(parts) >= 2 && strings.Join(parts[:len(parts)-2], ":") == owner
}

func compareStableAddresses(left, right string) (int, bool) {
	leftOrigin, leftComponents, leftPath, leftOK := stableAddressTuple(left)
	rightOrigin, rightComponents, rightPath, rightOK := stableAddressTuple(right)
	if !leftOK || !rightOK {
		return 0, false
	}
	if leftOrigin != rightOrigin {
		if leftOrigin < rightOrigin {
			return -1, true
		}
		return 1, true
	}
	for index := 0; index < len(leftComponents) && index < len(rightComponents); index++ {
		if leftComponents[index] != rightComponents[index] {
			if leftComponents[index] < rightComponents[index] {
				return -1, true
			}
			return 1, true
		}
	}
	if len(leftComponents) != len(rightComponents) {
		if len(leftComponents) < len(rightComponents) {
			return -1, true
		}
		return 1, true
	}
	if len(leftPath) != len(rightPath) {
		if len(leftPath) < len(rightPath) {
			return -1, true
		}
		return 1, true
	}
	for index := range leftPath {
		leftRank, leftRankOK := stableAddressKindRank(leftPath[index][0])
		rightRank, rightRankOK := stableAddressKindRank(rightPath[index][0])
		if !leftRankOK || !rightRankOK {
			return 0, false
		}
		if leftRank != rightRank {
			if leftRank < rightRank {
				return -1, true
			}
			return 1, true
		}
		if leftPath[index][1] != rightPath[index][1] {
			if leftPath[index][1] < rightPath[index][1] {
				return -1, true
			}
			return 1, true
		}
	}
	return 0, true
}

func stableAddressTuple(value string) (int, []string, [][2]string, bool) {
	parts := strings.Split(value, ":")
	if len(parts) < 3 || parts[0] != "ldl" {
		return 0, nil, nil, false
	}
	origin, pathStart := 0, 3
	components := []string{parts[2]}
	switch parts[1] {
	case "project":
	case "pack":
		if len(parts) < 4 {
			return 0, nil, nil, false
		}
		origin, pathStart, components = 1, 4, []string{parts[2], parts[3]}
	default:
		return 0, nil, nil, false
	}
	if (len(parts)-pathStart)%2 != 0 {
		return 0, nil, nil, false
	}
	path := make([][2]string, 0, (len(parts)-pathStart)/2)
	for index := pathStart; index < len(parts); index += 2 {
		path = append(path, [2]string{parts[index], parts[index+1]})
	}
	return origin, components, path, true
}

func stableAddressKindRank(kind string) (int, bool) {
	ranks := map[string]int{"entity-type": 0, "relation-type": 1, "layer": 2, "entity": 3, "relation": 4, "query": 5, "view": 6, "reference": 7, "column": 8, "constraint": 9, "row": 10, "parameter": 11, "table-column": 12, "export": 13}
	rank, ok := ranks[kind]
	return rank, ok
}

func validatePresenceRule(path string, object map[string]any, rule map[string]any) error {
	if values, ok := rule["required"].([]any); ok {
		for _, rawName := range values {
			name, _ := rawName.(string)
			if _, ok := object[name]; !ok {
				return fmt.Errorf("%s tagged alternative requires %s", path, name)
			}
		}
	}
	if values, ok := rule["forbidden"].([]any); ok {
		for _, rawName := range values {
			name, _ := rawName.(string)
			if _, ok := object[name]; ok {
				return fmt.Errorf("%s tagged alternative forbids %s", path, name)
			}
		}
	}
	if values, ok := rule["empty"].([]any); ok {
		for _, rawName := range values {
			name, _ := rawName.(string)
			items, ok := object[name].([]any)
			if !ok || len(items) != 0 {
				return fmt.Errorf("%s tagged alternative requires empty %s", path, name)
			}
		}
	}
	if values, ok := rule["non_empty"].([]any); ok {
		for _, rawName := range values {
			name, _ := rawName.(string)
			items, ok := object[name].([]any)
			if !ok || len(items) == 0 {
				return fmt.Errorf("%s tagged alternative requires non-empty %s", path, name)
			}
		}
	}
	if values, ok := rule["error_diagnostic"].([]any); ok {
		for _, rawName := range values {
			name, _ := rawName.(string)
			items, ok := object[name].([]any)
			if !ok {
				return fmt.Errorf("%s tagged alternative requires diagnostic array %s", path, name)
			}
			found := false
			for _, rawItem := range items {
				if item, ok := rawItem.(map[string]any); ok && item["severity"] == "error" {
					found = true
				}
			}
			if !found {
				return fmt.Errorf("%s tagged alternative requires an error diagnostic in %s", path, name)
			}
		}
	}
	if values, ok := rule["any_non_empty"].([]any); ok {
		found := false
		for _, rawName := range values {
			name, _ := rawName.(string)
			if items, ok := object[name].([]any); ok && len(items) > 0 {
				found = true
			}
		}
		if !found {
			return fmt.Errorf("%s tagged alternative requires at least one non-empty collection", path)
		}
	}
	if rules, ok := rule["allowed_values"].(map[string]any); ok {
		for property, rawValues := range rules {
			value, present := object[property]
			if !present {
				continue
			}
			allowed := false
			if values, ok := rawValues.([]any); ok {
				for _, candidate := range values {
					if value == candidate {
						allowed = true
					}
				}
			}
			if !allowed {
				return fmt.Errorf("%s tagged alternative forbids value %q for %s", path, value, property)
			}
		}
	}
	return nil
}

func validateDiffSource(path string, object map[string]any) error {
	if object["kind"] != "diff" {
		return nil
	}
	before, beforeOK := object["before"].(string)
	after, afterOK := object["after"].(string)
	if !beforeOK || !afterOK || before == "" || after == "" || before == after {
		return fmt.Errorf("%s diff source requires nonempty unequal before and after", path)
	}
	if _, hasQuery := object["query_address"]; !hasQuery {
		arguments, ok := object["arguments"].(map[string]any)
		if !ok || len(arguments) != 0 {
			return fmt.Errorf("%s diff source without query_address requires empty arguments", path)
		}
	}
	return nil
}

func validateProtocolOffer(path string, object map[string]any) error {
	rangeText, _ := object["supported_range"].(string)
	lower, upper, ok := parseProtocolVersionRange(rangeText)
	if !ok {
		return fmt.Errorf("%s has an invalid supported_range", path)
	}
	versions, _ := object["versions"].([]any)
	seen := map[string]bool{}
	for _, rawBinding := range versions {
		binding, _ := rawBinding.(map[string]any)
		versionText, _ := binding["version"].(string)
		version, _, valid := parseProtocolVersion(versionText)
		if !valid || compareProtocolVersions(version, lower) < 0 || compareProtocolVersions(version, upper) > 0 {
			return fmt.Errorf("%s version %q is outside supported_range", path, versionText)
		}
		if seen[versionText] {
			return fmt.Errorf("%s repeats protocol version %q", path, versionText)
		}
		seen[versionText] = true
	}
	return nil
}

func validateLimitCapability(path string, object map[string]any) error {
	defaultValue, defaultErr := strconv.ParseInt(fmt.Sprint(object["default_value"]), 10, 64)
	effective, effectiveErr := strconv.ParseInt(fmt.Sprint(object["effective_maximum"]), 10, 64)
	hard, hardErr := strconv.ParseInt(fmt.Sprint(object["hard_maximum"]), 10, 64)
	if defaultErr != nil || effectiveErr != nil || hardErr != nil || defaultValue > hard || effective > hard {
		return fmt.Errorf("%s default and effective limits must not exceed the hard maximum", path)
	}
	return nil
}

func protocolObject(value any) (map[string]any, bool) {
	object, ok := value.(map[string]any)
	return object, ok
}

func protocolString(object map[string]any, name string) string {
	value, _ := object[name].(string)
	return value
}

func equalProtocolValue(left, right any) bool { return reflect.DeepEqual(left, right) }

func protocolGenerationKey(raw any) (string, string, string, bool) {
	generation, ok := protocolObject(raw)
	if !ok {
		return "", "", "", false
	}
	handle, ok := protocolObject(generation["document_handle"])
	if !ok {
		return "", "", "", false
	}
	endpoint, endpointOK := handle["endpoint_instance_id"].(string)
	value, valueOK := handle["value"].(string)
	number, numberOK := generation["value"].(string)
	return endpoint, value, number, endpointOK && valueOK && numberOK
}

func sameProtocolGeneration(left, right any) bool {
	le, lh, lg, lok := protocolGenerationKey(left)
	re, rh, rg, rok := protocolGenerationKey(right)
	return lok && rok && le == re && lh == rh && lg == rg
}

func nextProtocolGeneration(base, proposed any) bool {
	be, bh, bg, bok := protocolGenerationKey(base)
	pe, ph, pg, pok := protocolGenerationKey(proposed)
	if !bok || !pok || be != pe || bh != ph {
		return false
	}
	b, err := strconv.ParseUint(bg, 10, 64)
	if err != nil || b == math.MaxUint64 {
		return false
	}
	p, err := strconv.ParseUint(pg, 10, 64)
	return err == nil && p == b+1
}

func protocolHasErrorDiagnostic(raw any) bool {
	values, ok := raw.([]any)
	if !ok {
		return false
	}
	for _, item := range values {
		object, _ := protocolObject(item)
		if object["severity"] == "error" {
			return true
		}
	}
	return false
}

func protocolBlobSize(value any) (uint64, error) {
	switch typed := value.(type) {
	case []any:
		var total uint64
		for _, item := range typed {
			size, err := protocolBlobSize(item)
			if err != nil || math.MaxUint64-total < size {
				return 0, errors.New("logical BlobRef byte count overflows uint64")
			}
			total += size
		}
		return total, nil
	case map[string]any:
		var total uint64
		if _, blob := typed["blob_id"].(string); blob {
			if _, digest := typed["digest"].(string); digest {
				if text, size := typed["size"].(string); size {
					parsed, err := strconv.ParseUint(text, 10, 64)
					if err != nil {
						return 0, err
					}
					total = parsed
				}
			}
		}
		for _, item := range typed {
			size, err := protocolBlobSize(item)
			if err != nil || math.MaxUint64-total < size {
				return 0, errors.New("logical BlobRef byte count overflows uint64")
			}
			total += size
		}
		return total, nil
	default:
		return 0, nil
	}
}

func protocolArrayItemCount(value any) (uint64, error) {
	switch typed := value.(type) {
	case []any:
		total := uint64(len(typed))
		for _, item := range typed {
			count, err := protocolArrayItemCount(item)
			if err != nil || math.MaxUint64-total < count {
				return 0, errors.New("array item count overflows uint64")
			}
			total += count
		}
		return total, nil
	case map[string]any:
		var total uint64
		for _, item := range typed {
			count, err := protocolArrayItemCount(item)
			if err != nil || math.MaxUint64-total < count {
				return 0, errors.New("array item count overflows uint64")
			}
			total += count
		}
		return total, nil
	default:
		return 0, nil
	}
}

func validatePagedResult(path string, object map[string]any) error {
	items, itemsOK := object["items"].([]any)
	page, pageOK := protocolObject(object["page"])
	if !itemsOK || !pageOK {
		return fmt.Errorf("%s must contain items and page", path)
	}
	returnedItems, ok := page["returned_items"].(string)
	if !ok || returnedItems != strconv.Itoa(len(items)) {
		return fmt.Errorf("%s.page.returned_items must equal the item count", path)
	}
	if cursor, present := page["next_cursor"]; present {
		cursorObject, ok := protocolObject(cursor)
		if !ok || !sameProtocolGeneration(object["document_generation"], cursorObject["document_generation"]) {
			return fmt.Errorf("%s.page.next_cursor is bound to another document generation", path)
		}
	}
	want, ok := page["returned_bytes"].(string)
	if !ok {
		return fmt.Errorf("%s.page.returned_bytes is invalid", path)
	}
	page["returned_bytes"] = "0"
	canonical, err := appendCanonicalJSON(nil, object)
	page["returned_bytes"] = want
	if err != nil {
		return err
	}
	blobs, err := protocolBlobSize(object)
	if err != nil || uint64(len(canonical)) > math.MaxUint64-blobs {
		return fmt.Errorf("%s logical response byte count overflows", path)
	}
	if want != strconv.FormatUint(uint64(len(canonical))+blobs, 10) {
		return fmt.Errorf("%s.page.returned_bytes is not the exact logical response byte count", path)
	}
	return nil
}

func validateQueryResult(path string, object map[string]any) error {
	result, ok := protocolObject(object["result"])
	if !ok {
		return fmt.Errorf("%s.result must be an object", path)
	}
	fields := [...]string{"seed_entity_addresses", "reached_entity_addresses", "traversed_entity_addresses", "path_relation_addresses", "induced_relation_addresses", "primary_entity_addresses", "selected_relation_addresses", "support_entity_addresses", "paths", "cycle_refs", "state_reads", "diagnostics"}
	var itemCount uint64
	for _, field := range fields {
		items, ok := result[field].([]any)
		if !ok {
			return fmt.Errorf("%s.result.%s must be an array", path, field)
		}
		if uint64(len(items)) > math.MaxUint64-itemCount {
			return fmt.Errorf("%s query result item count overflows", path)
		}
		itemCount += uint64(len(items))
	}
	returnedItems, ok := object["returned_items"].(string)
	if !ok || returnedItems != strconv.FormatUint(itemCount, 10) {
		return fmt.Errorf("%s.returned_items must equal the query result item count", path)
	}
	want, ok := object["returned_bytes"].(string)
	if !ok {
		return fmt.Errorf("%s.returned_bytes is invalid", path)
	}
	object["returned_bytes"] = "0"
	canonical, err := appendCanonicalJSON(nil, object)
	object["returned_bytes"] = want
	if err != nil {
		return err
	}
	blobs, err := protocolBlobSize(object)
	if err != nil || uint64(len(canonical)) > math.MaxUint64-blobs {
		return fmt.Errorf("%s logical response byte count overflows", path)
	}
	if want != strconv.FormatUint(uint64(len(canonical))+blobs, 10) {
		return fmt.Errorf("%s.returned_bytes is not the exact logical response byte count", path)
	}
	return nil
}

