func validateSemanticOperationInvariant(path string, object map[string]any) error {
	operation := protocolString(object, "operation")
	if operation == "create_subject" {
		kind := protocolString(object, "subject_kind")
		fields, ok := protocolObject(object["fields"])
		if !ok {
			return fmt.Errorf("%s.fields must be an object", path)
		}
		if kind == "view" {
			source, sourceOK := protocolObject(fields["source"])
			shape, shapeOK := protocolObject(fields["shape"])
			diff := fields["category"] == "diff"
			if !sourceOK || !shapeOK || (source["kind"] == "diff") != diff || (shape["kind"] == "diff") != diff {
				return fmt.Errorf("%s.fields view category, source, and shape disagree", path)
			}
			if shape["kind"] == "matrix" {
				cell, _ := protocolObject(shape["cell"])
				_, columns := cell["attribute_column_addresses"]
				if (cell["display"] == "attribute_summary") != columns {
					return fmt.Errorf("%s.fields.shape matrix attribute columns contradict display", path)
				}
			}
			if shape["kind"] == "flow" {
				_, columns := shape["lane_column_addresses"]
				if (shape["lane_by"] == "attribute") != columns {
					return fmt.Errorf("%s.fields.shape flow lane columns contradict lane_by", path)
				}
			}
		}
		if kind == "view_table_column" {
			source, sourceOK := protocolObject(fields["source"])
			if !sourceOK || source["kind"] == "query" || source["kind"] == "diff" {
				return fmt.Errorf("%s.fields.source is not a table column source", path)
			}
		}
		if kind == "entity_type_column" || kind == "relation_type_column" || kind == "query_parameter" {
			if format, present := fields["format"].(string); present && !map[string]bool{"cidr": true, "email": true, "hostname": true, "ipv4": true, "ipv6": true, "uri": true}[format] {
				return fmt.Errorf("%s.fields.format is not a canonical string format", path)
			}
			if err := validateQueryParameterConsistency(path+".fields", fields); err != nil {
				return err
			}
		}
		if kind == "view_export" {
			format, _ := fields["format"].(string)
			filename, _ := fields["filename"].(string)
			extension, exists := map[string]string{"json": ".json", "yaml": ".yaml", "svg": ".svg", "png": ".png", "pdf": ".pdf", "html": ".html", "csv": ".csv", "tsv": ".tsv", "xlsx": ".xlsx", "markdown": ".md", "pptx": ".pptx", "docx": ".docx", "mermaid": ".mmd", "bpmn": ".bpmn", "drawio": ".drawio"}[format]
			if !exists || filename == "" || filename == "." || filename == ".." || strings.ContainsAny(filename, "/\\\x00") || !strings.HasSuffix(filename, extension) || len(strings.TrimSuffix(filename, extension)) == 0 {
				return fmt.Errorf("%s.fields.filename is not the exact non-empty basename for %s", path, format)
			}
			if raw, present := fields["options"]; present {
				options, ok := protocolObject(raw)
				if !ok || options["kind"] != format {
					return fmt.Errorf("%s.fields.options.kind contradicts format", path)
				}
			}
			if raw, present := fields["exporter_profile"]; present {
				profile, ok := protocolObject(raw)
				if !ok || profile["format"] != format {
					return fmt.Errorf("%s.fields.exporter_profile.format contradicts format", path)
				}
			}
		}
	}
	return nil
}

func validateProtocolInvariant(path string, object map[string]any, profile string) error {
	switch profile {
	case "authoring_impact_entry":
		if object["capability"] == "graph:write" {
			address, ok := object["subject_address"].(string)
			facts, factsOK := protocolObject(object["graph_facts"])
			kind := protocolString(object, "subject_kind")
			actual, _, valid := stableAddressSubject(address)
			if !ok || !factsOK || !valid || actual != kind {
				return fmt.Errorf("%s graph:write entry lacks matching subject identity/facts", path)
			}
			flags, _ := facts["action_flags"].([]any)
			if len(flags) != 1 || flags[0] != object["action"] {
				return fmt.Errorf("%s graph action facts contradict entry action", path)
			}
		}
	case "authoring_impact":
		entries, _ := object["entries"].([]any)
		capabilities, _ := object["required_capabilities"].([]any)
		derived := map[string]bool{}
		for _, raw := range entries {
			entry, _ := protocolObject(raw)
			capability, _ := entry["capability"].(string)
			derived[capability] = true
		}
		if len(derived) != len(capabilities) {
			return fmt.Errorf("%s.required_capabilities contradict entries", path)
		}
		for _, raw := range capabilities {
			capability, _ := raw.(string)
			if !derived[capability] {
				return fmt.Errorf("%s.required_capabilities contradict entries", path)
			}
		}
	case "open_document_result":
		if !sameProtocolGeneration(object["document_generation"], map[string]any{"document_handle": object["document_handle"], "value": protocolString(object["document_generation"].(map[string]any), "value")}) {
			return fmt.Errorf("%s outer handle does not match document generation", path)
		}
	case "document_bound_input":
		if handle, present := object["document_handle"]; present && !sameProtocolGeneration(object["document_generation"], map[string]any{"document_handle": handle, "value": protocolString(object["document_generation"].(map[string]any), "value")}) {
			return fmt.Errorf("%s outer handle does not match document generation", path)
		}
		if cursor, present := object["cursor"]; present {
			cursorObject, ok := protocolObject(cursor)
			if !ok || !sameProtocolGeneration(object["document_generation"], cursorObject["document_generation"]) {
				return fmt.Errorf("%s.cursor is bound to another document generation", path)
			}
		}
	case "paged_result":
		return validatePagedResult(path, object)
	case "query_result":
		return validateQueryResult(path, object)
	case "view_data_result":
		return validateViewDataResult(path, object)
	case "bounded_text_chunk":
		blob, _ := protocolObject(object["blob"])
		offset, e1 := strconv.ParseUint(protocolString(object, "offset"), 10, 64)
		total, e2 := strconv.ParseUint(protocolString(object, "total_bytes"), 10, 64)
		size, e3 := strconv.ParseUint(protocolString(blob, "size"), 10, 64)
		if e1 != nil || e2 != nil || e3 != nil || offset > total || size > total-offset || blob["media_type"] != "text/plain; charset=utf-8" || blob["lifetime"] != "request" {
			return fmt.Errorf("%s has an invalid bounded UTF-8 chunk range", path)
		}
		if offset == 0 && size == total && blob["digest"] != object["full_digest"] {
			return fmt.Errorf("%s complete chunk digest must equal full_digest", path)
		}
	case "source_edit":
		kind := protocolString(object, "kind")
		blob, hasBlob := protocolObject(object["replacement_blob"])
		if hasBlob && (blob["digest"] != object["after_digest"] || blob["media_type"] != "text/plain; charset=utf-8" || blob["lifetime"] != "request") {
			return fmt.Errorf("%s replacement blob is not reconstructable", path)
		}
		if kind == "move" {
			if object["before_digest"] != object["after_digest"] || equalProtocolValue(object["before_module"], object["after_module"]) {
				return fmt.Errorf("%s move must preserve bytes and change module identity", path)
			}
		}
	case "preview_result":
		if object["status"] == "valid" {
			if protocolHasErrorDiagnostic(object["diagnostics"]) {
				return fmt.Errorf("%s valid preview contains an error diagnostic", path)
			}
			impact, _ := protocolObject(object["authoring_impact"])
			semanticDiff, _ := protocolObject(object["semantic_diff"])
			sourceDiff, _ := protocolObject(object["source_diff"])
			hashes, _ := protocolObject(object["resulting_hashes"])
			if object["authoring_impact_digest"] != impact["impact_digest"] || !equalProtocolValue(object["required_authoring_capabilities"], impact["required_capabilities"]) || impact["semantic_diff_hash"] != semanticDiff["digest"] || impact["source_diff_hash"] != sourceDiff["digest"] || impact["resulting_definition_hash"] != hashes["definition_hash"] {
				return fmt.Errorf("%s preview integrity fields disagree", path)
			}
			preview, _ := protocolObject(object["preview_id"])
			endpoint, _, _, _ := protocolGenerationKey(object["base_generation"])
			if preview["endpoint_instance_id"] != endpoint || !nextProtocolGeneration(object["base_generation"], object["proposed_generation"]) {
				return fmt.Errorf("%s preview identities disagree", path)
			}
		} else if len(object["conflicts"].([]any)) == 0 && !protocolHasErrorDiagnostic(object["diagnostics"]) {
			return fmt.Errorf("%s invalid preview requires a conflict or error diagnostic", path)
		}
	case "apply_input":
		preview, _ := protocolObject(object["preview_id"])
		endpoint, _, _, ok := protocolGenerationKey(object["base_generation"])
		if !ok || preview["endpoint_instance_id"] != endpoint {
			return fmt.Errorf("%s preview and base generation endpoints disagree", path)
		}
	case "apply_result":
		impact, _ := protocolObject(object["authoring_impact"])
		sourceDiff, _ := protocolObject(object["source_diff"])
		hashes, _ := protocolObject(object["resulting_hashes"])
		if impact["source_diff_hash"] != sourceDiff["digest"] || impact["resulting_definition_hash"] != hashes["definition_hash"] {
			return fmt.Errorf("%s apply integrity fields disagree", path)
		}
	case "semantic_operation":
		return validateSemanticOperationInvariant(path, object)
	default:
		return fmt.Errorf("%s has unknown protocol invariant %q", path, profile)
	}
	return nil
}

func appendCanonicalJSON(destination []byte, value any) ([]byte, error) {
	switch typed := value.(type) {
	case nil:
		return append(destination, "null"...), nil
	case bool:
		return strconv.AppendBool(destination, typed), nil
	case string:
		var buffer bytes.Buffer
		encoder := json.NewEncoder(&buffer)
		encoder.SetEscapeHTML(false)
		if err := encoder.Encode(typed); err != nil {
			return nil, err
		}
		return append(destination, bytes.TrimSuffix(buffer.Bytes(), []byte{'\n'})...), nil
	case json.Number:
		text := typed.String()
		if !regexp.MustCompile(`^(0|-[1-9][0-9]*|[1-9][0-9]*)$`).MatchString(text) {
			return nil, errors.New("protocol canonical JSON permits only canonical integer numbers")
		}
		return append(destination, text...), nil
	case []any:
		destination = append(destination, '[')
		for index, item := range typed {
			if index != 0 {
				destination = append(destination, ',')
			}
			var err error
			destination, err = appendCanonicalJSON(destination, item)
			if err != nil {
				return nil, err
			}
		}
		return append(destination, ']'), nil
	case map[string]any:
		keys := make([]string, 0, len(typed))
		for key := range typed {
			keys = append(keys, key)
		}
		sort.Slice(keys, func(i, j int) bool {
			left, right := utf16.Encode([]rune(keys[i])), utf16.Encode([]rune(keys[j]))
			for index := 0; index < len(left) && index < len(right); index++ {
				if left[index] != right[index] {
					return left[index] < right[index]
				}
			}
			return len(left) < len(right)
		})
		destination = append(destination, '{')
		for index, key := range keys {
			if index != 0 {
				destination = append(destination, ',')
			}
			var err error
			destination, err = appendCanonicalJSON(destination, key)
			if err != nil {
				return nil, err
			}
			destination = append(destination, ':')
			destination, err = appendCanonicalJSON(destination, typed[key])
			if err != nil {
				return nil, err
			}
		}
		return append(destination, '}'), nil
	default:
		return nil, fmt.Errorf("unsupported canonical JSON value %T", value)
	}
}
